INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('3c2b45d3-b973-42a8-a3b4-a5c070580510', '3dx-industries', '3DX Industries', 'https://3dxindustries.com', '6920 Salashan Pkwy D-101, Ferndale, WA 98248', 'Ferndale', 'United States', 48.8168, -122.595551, ARRAY['binder-jetting'], ARRAY['stainless-steel','nickel','bronze-infiltrated-steel'], NULL, NULL, 'northamerica', true, false, 0, 0, '3DX Industries specializes in advanced manufacturing, offering both additive and subtractive processes. They provide 3D metal printing, FDM, MSLA, and CNC machining for rapid prototyping and full-scale production. The company serves various industries including green energy, medical, aerospace, automotive, and consumer goods.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-22 18:00:36.57+00', 0, 1, '2025-11-11 15:57:15.934661+00', '2026-03-12 08:09:32.689977+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('3f65e631-27fd-48a9-b5d2-e5eb626fc4e5', 'hyperion-systems', 'Hyperion Systems', 'https://www.hyperionsystems.com.au', 'Perth, Western Australia, Australia', 'Perth', 'Australia', -31.9558967, 115.8605784, ARRAY['fdm'], ARRAY['petg','asa','pp','hdpe','tpu','tpe','recycled-materials','sustainable-materials'], NULL, NULL, NULL, true, false, 0, 0, 'Hyperion Systems specializes in deployable, large-format 3D printing units for rapid, large-scale manufacturing. They offer containerized and robotic extrusion systems, along with integrated software, for flexible production. The company provides full lifecycle support, including installation, training, and material supply, serving sectors like marine and construction.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '59442a5f-ad35-40d3-8bc1-4752790dfb28', '2026-01-30 14:45:49.549+00', 80, 0, '2025-10-25 16:41:25.326792+00', '2026-03-21 13:59:10.329628+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('14a60c5e-0144-4ca3-9471-af66c2781f77', 'parts-on-demand', 'Parts On Demand – Industrial 3D Printing & Digital Productio', 'https://www.partsondemand.nl', 'Utrecht, Netherlands', 'Utrecht', 'Netherlands', 52.1057913, 5.0815008, ARRAY['sls'], ARRAY['nylon','food-safe-nylon'], NULL, 'free-listing', 'europe', true, false, 0, 0, 'Parts on Demand is an industrial 3D printing partner specializing in Selective Laser Sintering (SLS) for real production. They focus on delivering high-quality, functional parts quickly, whether for small batches or large series. The company aims to be a partner in making products smarter, more efficient, and better for market leaders.', '{"capacity_notes":"Capable of producing series from 1 to 100,000 pieces, indicating a focus on both prototyping and mass production.","certifications":[],"industries_served":["Machine Building","Electronics","Architecture","Medical","Robotics","Assembly","Drones"],"overview":"Parts on Demand is an industrial 3D printing partner specializing in Selective Laser Sintering (SLS) for real production. They focus on delivering high-quality, functional parts quickly, whether for small batches or large series. The company aims to be a partner in making products smarter, more efficient, and better for market leaders.","unique_value":"Parts on Demand differentiates itself by focusing on true industrial-scale production with SLS, handling series from 1 to 100,000 pieces. They offer expertise in food-contact applications adhering to EC1935/2004 or FDA standards, and provide solutions for production tools, molds, machine parts, and end-of-arm tooling."}', '{"TechnologyID":["fdm","sls","mjf"],"affiliatelinkid":"https://www.partsondemand.eu","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"Schaverijstraat 9D, 3534 AS Utrecht, Netherlands","building":""},"thermoplasticid":["tpu-mjf","polypropylene-mjf","pa11-sls","pa-af","pa-12","nylon-pa-12-blue-metal","nylon-pa-12","nylon-12-mineral-filled-hst","nylon-12-glass-bead-filled-gf","nylon-12-flame-retardant-fr","nylon-12-aluminum-filled-af","nylon-12"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, true, '{}', '2af56425-bb25-4ce2-8c4a-f6aef6217ed3', '2026-02-05 13:05:35.802+00', 87, 0, '2025-10-23 16:57:32.640307+00', '2026-03-23 14:39:08.17519+00') ON CONFLICT (id) DO NOTHING;
