INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('ae811dfd-af2f-4381-96e5-5025587c978b', 'discovered-29d76141', 'Proto3000', 'https://proto3000.com', 'Canada', NULL, 'Canada', NULL, NULL, ARRAY['lpbf','sla','sls','dlp','binder-jetting','mjf'], ARRAY['metal','resin','polymer','nylon','nylon-11','ceramic'], NULL, NULL, NULL, true, false, 0, 0, 'Proto3000 is a premier provider of additive manufacturing, 3D printing services, and metrology solutions. They offer end-to-end product development and manufacturing services, leveraging state-of-the-art additive manufacturing and metrology technology to tackle complex engineering challenges. The company provides a full line of 3D printers, 3D scanners, and related services to help bring concepts to finished products.', '{"capacity_notes":"Proto3000 operates one of the largest fleets of HP 3D printing systems in Canada and the US Northeast, indicating significant production capacity for MJF technology.","certifications":[],"industries_served":["Aerospace","Automotive","Consumer Goods","Consumer Electronics","Commercial Products / Industrial Machinery","Dental / Orthodontics","Education","Government / Military","Medical","Media / Entertainment"],"overview":"Proto3000 is a premier provider of additive manufacturing, 3D printing services, and metrology solutions. They offer end-to-end product development and manufacturing services, leveraging state-of-the-art additive manufacturing and metrology technology to tackle complex engineering challenges. The company provides a full line of 3D printers, 3D scanners, and related services to help bring concepts to finished products.","unique_value":"Proto3000 distinguishes itself by offering end-to-end product development and manufacturing solutions, encompassing 3D design, additive manufacturing, 3D scanning, and quality inspection. They are an HP Multi Jet Fusion Production Partner with one of the largest fleets of HP 3D printing systems in Canada and the US Northeast, certified for production at scale."}', '{}'::jsonb, NULL, NULL, false, true, '{}', '714df434-bfec-4dc7-8071-15b684e92414', '2026-02-10 16:01:03.553+00', 88, 0, '2025-12-26 19:15:50.798825+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
