INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('57ebb37b-0d2a-4116-9487-6a2295a29909', 'hlh-prototypes', 'HLH Prototypes', 'https://www.hlhprototypes.com', 'Shenzhen, China', 'Shenzhen', 'China', 22.535383, 114.05471, ARRAY['3d-printing','sla','sls','cnc-machining','injection-molding','vacuum-casting','sheet-metal-work','die-casting','rapid-tooling','rim'], ARRAY['plastic','metal','composites','rubber','aluminum','stainless-steel','carbon-fiber','urethane'], NULL, NULL, NULL, true, false, 0, 0, 'HLH Prototypes specializes in rapid prototyping and low-volume manufacturing services, offering solutions from initial prototypes to production parts. They provide 3D printing (SLA, SLS), CNC machining, injection molding, and vacuum casting, serving industries like automotive, medical, and consumer products globally. With facilities in Shenzhen and Dongguan, China, HLH focuses on delivering high-quality parts quickly.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '70ad71f3-c876-44f0-8cb6-d25f2c271283', '2026-01-21 07:00:55.807+00', 0, 1, '2025-11-11 15:08:51.871431+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('2b4b62c0-05f1-4e30-99bb-124e9d0e2184', 'discovered-e29d8ec5', 'CRP USA', 'https://crp-group.com', 'Mooresville, NC, United States', 'Mooresville', 'United States', 35.5848596, -80.8100724, ARRAY['sls'], ARRAY['windform-sp','windform-xt-2.0','windform-gt','windform-rs','windform-lx-3.0'], NULL, NULL, NULL, true, false, 0, 0, 'SLS specialist using proprietary Windform composite materials (carbon fiber and glass fiber reinforced thermoplastics). Roots in Formula One racing. First fully 3D printed CubeSat. Aerospace/defense/motorsport focus. ISO certified.', '{"capacity_notes":"CRP Group operates a global manufacturing network with facilities in Italy (CRP Technology, CRP Meccanica), USA (CRP USA), and UAE (CRP Gulf), indicating significant production capacity across multiple locations.","certifications":["ISO 9001","AS9100","EN9100","ITAR registered"],"industries_served":["Aerospace","Defense","UAV","Motorsport","Robotics","Automotive","Medical","Marine"],"overview":"CRP USA is part of the CRP Group, an advanced manufacturing gateway specializing in CNC machining and additive manufacturing. With over 50 years of motorsport heritage, they deliver high-performance parts using proprietary Windform materials and DMLS for demanding sectors. The company focuses on precision, speed, and reliability for aerospace, defense, and automotive applications.","unique_value":"CRP USA leverages over 50 years of motorsport DNA, offering advanced manufacturing solutions with a strong emphasis on proprietary Windform® additive manufacturing materials. They provide integrated services including DMLS and CNC machining, alongside strategic consulting for Design for Additive Manufacturing (DfAM) and topological optimization to create lightweight, robust components."}', '{}'::jsonb, NULL, 'Not specified', false, false, ARRAY['ISO 9001'], 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-06 07:00:59.959+00', 93, 0, '2026-02-02 12:22:49.614381+00', '2026-03-23 14:45:44.314518+00') ON CONFLICT (id) DO NOTHING;
