INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('6717df62-91b1-4cc6-a9b4-48cb4b248b21', 'robot-faber', 'Robot faber', 'https://robotfaber.com', 'France', NULL, 'France', 13.4, 52.52, ARRAY['fdm'], ARRAY['ceramic','pet','nylon'], NULL, NULL, NULL, true, false, 0, 0, 'Robot Faber specializes in advanced digital manufacturing, leveraging computational design and parametric programming to create complex 3D forms. They offer large-format 3D printing services, particularly in ceramics and plastics, alongside 2D/3D CNC machining and digital turning. The company focuses on developing custom solutions and algorithms to bridge design concepts with industrial production.', '{"capacity_notes":"Specializes in large-format 3D printing and medium-format ceramic printing, developing internal systems for material extraction. Utilizes 6-axis robots and 3-4 axis CNC machines for production.","certifications":[],"industries_served":["Art","Architecture","Design"],"overview":"Robot Faber specializes in advanced digital manufacturing, leveraging computational design and parametric programming to create complex 3D forms. They offer large-format 3D printing services, particularly in ceramics and plastics, alongside 2D/3D CNC machining and digital turning. The company focuses on developing custom solutions and algorithms to bridge design concepts with industrial production.","unique_value":"Robot Faber''s unique value lies in its expertise in computational and parametric design, developing proprietary algorithms and internal solutions for medium-format ceramic 3D printing. They utilize 5-axis 3D printing techniques for large-format projects, offering a specialized approach to complex artistic and architectural creations."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'e1f5c58c-c518-4525-92f7-de100c711be1', '2026-02-11 04:00:43.825+00', 83, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('98ae14c1-e40e-4320-a54f-29472dabda7d', 'discovered-e2f4e274', 'BigRep Partlab', 'https://bigrep.com', 'Gneisenaustraße 66, 10961 Berlin, Germany', 'Berlin', 'Germany', 52.4895, 13.3886, ARRAY['fdm'], ARRAY['pla','petg','abs','asa','pa6','pa66','tpu','pa12-cf'], NULL, NULL, NULL, true, false, 0, 0, 'BigRep Partlab is the on-demand 3D printing service from BigRep GmbH, producing large-format FFF parts up to one cubic metre on BigRep''s own industrial printers. Customers upload STL/STEP/OBJ files, receive a quote within 48 hours, and the team prints, post-processes and ships the parts. Materials span standard polymers (PLA, PETG, ABS, ASA), engineering-grade nylons (PA6/66) and TPU 98A, plus fibre-reinforced composites (PA12 CF, HI-TEMP CF).', '{"overview":"BigRep Partlab is BigRep GmbH''s in-house large-format 3D printing service, leveraging the company''s own industrial FFF printer fleet (BigRep ONE, STUDIO, PRO, ALTRA 280, IPSO 105, VIIO 250) to deliver functional prototypes, tooling, moulds and end-use parts.","unique_value":"Single, seamless FFF parts up to 1 m³ — no cutting and gluing. Backed by BigRep''s engineering team and proprietary filament line.","capacity_notes":"Build volumes up to 1 m³ on a single part. Quote within 48 hours. Accepts STL, STEP, OBJ files.","industries_served":["Aerospace","Automotive","Manufacturing","Education & Research","Consumer Goods","Construction","Defense","Energy","Marine","Railway","Creative"],"headquarters":"Gneisenaustraße 66, 10961 Berlin, Germany","contact":{"email":"info@bigrep.com","phone":"+49 30 20 84 82 60","fax":"+49 30 20 84 82 699"},"other_offices":["BigRep America Inc., 40 Nagog Park Suite 100-105, Acton, MA 01720, USA (+1 781 281 0569)","BigRep Private Ltd., 201 Henderson Road, Apex@Henderson #03-13, Singapore 159545 (+65 6909 8191)","HAGE3D GmbH (subsidiary), Kratkystraße 2, 8020 Graz, Austria"],"certifications":[]}', '{}'::jsonb, NULL, NULL, false, false, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-04-26 21:00:00+00', 100, 0, '2025-12-26 19:43:53.496828+00', '2026-04-26 21:00:00+00') ON CONFLICT (id) DO NOTHING;
