INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0d24da41-9c7b-46a3-9a42-07fba33395cd', 'morf3d', 'Morf3D (Nikon AM Synergy)', 'https://morf3d.com', NULL, NULL, NULL, NULL, NULL, '{}', '{}', NULL, NULL, NULL, false, false, 0, 0, 'Morf3D''s website is currently under renovation, limiting access to detailed information about their services and capabilities. As a result, specific technologies, materials, and company specializations cannot be determined from the current site.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-01-28 05:00:43.406+00', 0, 5, '2025-11-11 15:59:48.061666+00', '2026-01-28 05:00:43.604238+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('216b8e7f-c797-496c-8e5e-42d2ae93cc6f', 'discovered-aee37354', '3D MicroPrint', 'https://3dmicroprint.com', 'Chemnitz, Germany', 'Chemnitz', 'Germany', 50.8323531, 12.918914, ARRAY['micro-slm','micro-laser-sintering'], ARRAY['stainless-steel','stainless-steel-316l','stainless-steel-17-4ph','titanium','titanium-ti-6al-4v','copper','inconel-718','platinum','gold','cobalt','chrome','tungsten'], NULL, NULL, NULL, true, false, 0, 0, 'Specialist in Micro Laser Sintering (µSLM) for micro-scale metal parts with precision down to 5-10 µm and wall thickness <50µm. Cooperation between EOS GmbH and 3D-Micromac AG, founded 2013. ISO 9001:2015 certified, ISO 13485 compliant. Focus: medical, aerospace, semiconductor.', '{"capacity_notes":"3D MicroPrint has been in the market for 12 years, serving over 300 customers worldwide and completing more than 10,000 projects. They utilize their proprietary DMP70 and DMP120 Micro Laser Sintering machines, offering a build volume of 60 x 60 x 45 mm (LxBxH), layer thickness < 10 µm, part density > 99.5%, roughness Ra: 1 µm, minimum wall thickness 30 µm, resolution accuracy 5 µm, and focus diameter < 30 µm.","certifications":["ISO 9001:2015","ISO 13485"],"industries_served":["Aerospace","Medical","Electronics","Thermal Engineering","Jewelry","Fluid Technology","Metrology","Semiconductor Industry","Micromechanics","Chemical Industry","Nuclear Industry"],"overview":"3D MicroPrint specializes in the additive manufacturing of high-precision micro metal components using their innovative Micro Laser Sintering technology. With over 10 years of experience, the company continuously develops micro and miniature component production, serving various industries. They offer a comprehensive service from design consultation to prototyping, series production, and exclusive material developments, optimizing quality, cost, and functionality for their clients.","unique_value":"3D MicroPrint''s unique Micro Laser Sintering (MLS) technology combines additive manufacturing with micro-machining to produce metallic micro-parts with exceptional precision, detail resolution (down to 5-10 micrometers), and surface quality. Their ''Print-as-One'' solution allows for the production of complex assemblies as single, integrated parts, eliminating assembly and tolerance issues, and they offer proprietary MLS machines (DMP70, DMP120) for sale."}', '{}'::jsonb, NULL, NULL, false, false, ARRAY['ISO 9001:2015','ISO 13485'], '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-02-06 06:00:49.474+00', 97, 1, '2026-02-02 12:22:49.614381+00', '2026-03-23 14:42:26.320101+00') ON CONFLICT (id) DO NOTHING;
