INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('00ff77bf-425c-44e6-98e6-bc92c6955e08', 'mx3d', 'MX3D – Robotic WAAM Metal 3D Printing Solutions', 'https://mx3d.com', 'Amsterdam, Netherlands', 'Amsterdam', 'Netherlands', 52.397559, 4.8523576, ARRAY['waam'], ARRAY['stainless-steel','steel'], NULL, 'free-listing', 'europe', true, false, 0, 0, 'MX3D specializes in robotic 3D metal printing using Wire Arc Additive Manufacturing (WAAM) technology. They offer M-Metal AM Systems for in-house production and print high-quality metal parts on demand up to 20,000 kg. The company serves various industries including Nuclear, Maritime, Oil and Gas, Construction, and Art and Design, with certified printing to strict industry standards.', NULL, '{"TechnologyID":["ded"],"affiliatelinkid":"https://mx3d.com","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"Dynamostraat 46, 1014 BK Amsterdam, Netherlands","building":""},"metalid":["titanium-ti-6al-4v","steel","stainless-steel-316l","inconel-625","gold-plated-brass","maraging-steel","aluminum-aisi10mg","inconel-718"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', '2af56425-bb25-4ce2-8c4a-f6aef6217ed3', '2026-01-23 12:58:32.568+00', 95, 1, '2025-10-23 16:57:33.082282+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
