INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('68aa0563-b6fe-42b7-bf86-d356b219a290', 'hyperion-robotics', 'Hyperion Robotics', 'https://hyperionrobotics.com', 'Espoo, Finland', 'Espoo', 'Finland', 60.2049651, 24.6559808, ARRAY['robotic-manufacturing','computational-design','robotic-automation'], ARRAY['concrete'], NULL, NULL, NULL, true, false, 0, 0, 'Hyperion Robotics specializes in transforming concrete infrastructure construction to be more sustainable and efficient. They utilize computational design, robotic manufacturing, and advanced low-carbon concrete to deliver high-performance foundations. Their solutions reduce emissions, material use, and energy consumption for clients in the energy and infrastructure sectors.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'eada246c-aa74-428d-84bc-e89f3c35743a', '2026-02-01 11:00:54.141+00', 65, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('a37b77db-3e6f-4f18-8a99-a4a208a76c83', 'studiobenkert', 'studiobenkert', 'https://studiobenkert.com', 'Germany', NULL, 'Germany', 50.0818105, 10.570198, ARRAY['fdm'], ARRAY['recycled-materials'], NULL, NULL, NULL, true, false, 0, 0, 'Studiobenkert specializes in large-scale 3D printing, offering innovative and precise solutions. They focus on using recycled and upcycled materials, emphasizing sustainability and German manufacturing quality. The company aims to make creative visions tangible through their advanced 3D printing capabilities.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-01-23 12:46:00.851+00', 78, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('51d28b94-2aa8-47d1-a97e-7601cc6d6d8e', 'pixom', 'PIXOM', 'http://www.pixom.pt', 'R. Dr. Francisco Silva Pinto 45, 4445-403 Ermesinde, Portugal', 'Ermesinde', 'Portugal', 41.1502195, -8.6103497, ARRAY['fgf','robotic-3d-printing'], ARRAY['recycled-plastic','sustainable-materials'], NULL, NULL, 'europe', true, false, 0, 0, 'PIXOM specializes in turning pixels into atoms, creating extraordinary and sustainable objects through (re)generative design, artificial intelligence, and robotic manufacturing. They focus on humanizing technology to improve comfort and well-being, integrating computational design and robotics. The company emphasizes conscious innovation with sustainable materials and 3D printing.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '14c64e1b-59d7-4cad-9a98-20c6a62186fd', '2026-01-26 19:00:43.352+00', 68, 0, '2025-10-25 16:41:25.326792+00', '2026-03-16 08:12:43.764337+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('ec24c5bf-84ce-44af-bce9-eea9209502ba', 'discovered-ml53jqgi-77s7', 'Hankook Precision Works', 'https://hankook-precisionworks.com', NULL, NULL, 'South Korea', NULL, NULL, ARRAY['Metal 3D Printing'], ARRAY['Metal'], NULL, NULL, NULL, false, false, 0, 0, 'Hankook Precision Works is the first tire mold manufacturer in Korea to use metal 3D printing to create complex forms and reduce processing time. They also offer expertise in developing finished products using this technology.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'd6e408bf-cd28-4e01-9eb1-94ddcde34969', '2026-02-10 06:01:40.793+00', 0, 5, '2026-02-02 11:38:49.70459+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0e17b8e0-8810-449f-bd2a-caa0e4a5f2f6', 'discovered-ml53jtpr-uzma', 'InssTek', 'https://insstek.com', 'Seoul, South Korea', 'Seoul', 'South Korea', 36.3497007, 127.3849016, ARRAY['waam'], ARRAY['inconel-939','inconel-625','inconel-718','aluminum-bronze','c-103','stainless-steel-316l','stellite-6','carbon-steel','titanium-ti-6al-4v','nimonic-75','nickel-based-superalloys','high-entropy-alloys','metal-matrix-composites','functionally-graded-materials'], NULL, NULL, NULL, true, false, 0, 0, 'InssTek is a South Korean company specializing in Direct Energy Deposition (DED) metal 3D printing technology. They develop and manufacture DED systems, including their proprietary DMT® technology, for high-functional component production, repair, and special coating applications. The company focuses on pushing the boundaries of additive manufacturing, particularly for complex and multi-material metal parts.', '{"capacity_notes":"InssTek offers various DED systems, including the MX-Fab series (MX-Fab1 with 500x600x400mm build volume, MX-Fab3 with 800x1000x700mm build volume) and the large-scale NARAE System capable of producing parts up to 3.5m diameter and 7.5m height. Their systems feature multi-material capabilities (up to 6 hoppers) and 5-axis AM with variable beam sizes.","certifications":["ISO 13485:2016"],"industries_served":["Aerospace","Energy","Maritime","Powerplant","Medical Implants","Automotive","Defense","Research & Development"],"overview":"InssTek is a South Korean company specializing in Direct Energy Deposition (DED) metal 3D printing technology. They develop and manufacture DED systems, including their proprietary DMT® technology, for high-functional component production, repair, and special coating applications. The company focuses on pushing the boundaries of additive manufacturing, particularly for complex and multi-material metal parts.","unique_value":"InssTek''s unique value lies in its proprietary DMT® (Direct Metal Tooling) technology and CVM (Clogged Vibration Method) powder feeding system, which enables precise multi-material deposition with up to six different powders simultaneously. Their MX-Lab system, combined with Material Designer software, allows for rapid alloy scanning and development, significantly reducing the time required for high entropy alloy creation from weeks to hours."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'd6e408bf-cd28-4e01-9eb1-94ddcde34969', '2026-02-08 23:00:26.336+00', 95, 0, '2026-02-02 11:38:53.917737+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('fd4ec32d-f1dc-407f-b2aa-71c4a25fd1ef', 'nagami', 'Nagami', 'https://nagami.design', 'Ávila, Spain', 'Ávila', 'Spain', 40.656478, -4.7002172, ARRAY['fdm'], ARRAY['petg','recycled-plastic'], NULL, NULL, NULL, true, false, 0, 0, 'Nagami transforms design through large-format 3D printing, utilizing recycled and recyclable materials to create unique and sustainable pieces. They specialize in eco-innovative design and architectural solutions, pushing the boundaries of technology with recycled plastics. Since 2016, Nagami has been creating sustainable designs for various applications, from furniture to large-scale installations.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '8d5626d2-6740-41c5-8ea0-ac31a6d648b0', '2026-02-01 06:01:38.53+00', 92, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('37314630-9441-4b90-a69d-f5c08f2e45b3', 'poolp', 'POOLP', 'https://www.poolp.eu', NULL, NULL, NULL, 13.4, 52.52, ARRAY['fdm'], ARRAY['recycled','bio-sourced'], NULL, NULL, NULL, true, false, 0, 0, 'Poolp specializes in providing fully customized, sustainable, and large-scale 3D printing solutions. They support architects, designers, and various industries from concept to production, focusing on efficiency, on-demand manufacturing, and a circular economy approach. The company leverages robotic Large-Format Additive Manufacturing (LFAM) and advanced computational design to create complex geometries with minimal waste.', '{"capacity_notes":"Utilizes robotic Large-Format Additive Manufacturing (LFAM) for scalable and fast production, enabling large-scale, complex forms with minimal material waste.","certifications":[],"industries_served":["Architecture","Design","Retail Experiences","Events","Set Design","Interior Architecture","Office Spaces","Ephemeral Installations"],"overview":"Poolp specializes in providing fully customized, sustainable, and large-scale 3D printing solutions. They support architects, designers, and various industries from concept to production, focusing on efficiency, on-demand manufacturing, and a circular economy approach. The company leverages robotic Large-Format Additive Manufacturing (LFAM) and advanced computational design to create complex geometries with minimal waste.","unique_value":"Poolp''s unique value lies in its focus on robotic Large-Format Additive Manufacturing (LFAM) combined with advanced computational design services for optimized, large-scale geometries. They are dedicated to pioneering material innovation, specifically developing and testing new recycled and bio-sourced materials for sustainable and high-performing solutions."}', '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-02-11 05:00:38.174+00', 78, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('b1113130-d469-4d2a-8060-cfd21104b71d', 'printerior', 'Printerior', 'https://printeriordesigns.com', 'Germany', NULL, 'Germany', 13.4, 52.52, ARRAY['fdm','sla','sls'], ARRAY['pla','petg'], NULL, NULL, NULL, true, false, 0, 0, 'Printerior offers on-demand 3D printing services for prototypes, products, and artwork, utilizing FDM, SLA, and SLS technologies. The company specializes in sustainable manufacturing by using 100% recycled PLA (rPLA) and PET-G filaments. They also provide a recycling program for 3D printing waste, fostering a circular economy approach to additive manufacturing.', '{"capacity_notes":null,"certifications":[],"industries_served":[],"overview":"Printerior offers on-demand 3D printing services for prototypes, products, and artwork, utilizing FDM, SLA, and SLS technologies. The company specializes in sustainable manufacturing by using 100% recycled PLA (rPLA) and PET-G filaments. They also provide a recycling program for 3D printing waste, fostering a circular economy approach to additive manufacturing.","unique_value":"Printerior''s unique value lies in its strong commitment to sustainability, offering 3D printing services primarily with 100% recycled PLA (rPLA) and PET-G filaments. They actively promote a circular economy by providing a recycling program for 3D printer waste, allowing customers to earn rewards points for their contributions."}', '{}'::jsonb, NULL, 'same day', false, true, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-02-11 00:00:38.582+00', 83, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
