INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('c74f4417-53df-4d1c-88cd-59056a768ce8', 'sculpto', 'Sculpto', 'https://sculpto-shop.com/pages/3d-print-on-demand', 'Aarhus, Denmark', 'Aarhus', 'Denmark', 55.6867243, 12.5700724, ARRAY['fdm'], '{}', NULL, NULL, NULL, true, false, 0, 0, 'Sculpto is a Danish 3D printing supplier specializing exclusively in FDM technology, leveraging 8 years of experience and a large print farm with over 200 printers. They offer cost-effective 3D printing services for production runs of 1 to 5,000 items, as well as rapid prototyping, with a focus on quality and precision. Sculpto also provides expertise in redesign and optimization for 3D print production.', NULL, '{}'::jsonb, NULL, '1-3 days', false, false, '{}', '008671b2-ad05-4e60-8622-df1af2c43df2', '2026-02-01 12:00:46.377+00', 82, 0, '2025-11-03 19:16:30.40783+00', '2026-03-21 13:57:10.425752+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('dea9911e-81e0-4108-90f0-6ab4dfb7b1d9', 'treatstock-habitadd', 'HabitAdd', 'https://habitadd.bg', 'Bulgaria', NULL, 'Bulgaria', 42.6977028, 23.3217359, ARRAY['sls','mjf','slm','dmls','fdm','dlp','sla','ded','binder-jetting'], ARRAY['metals','polymers','nylon-pa-12','nylon-12-glass-filled','resin','ceramic','sand','composites'], NULL, NULL, NULL, true, false, 0, 0, 'HabitAdd OOD is a Bulgarian company specializing in engineering, consulting, and manufacturing services within additive manufacturing technologies, also known as 3D Printing. They offer a comprehensive approach to engineering and production solutions for various industries, aiming to optimize processes and products through their network of partners. Their services are built on providing specific engineering know-how in the application and development of 3D printing solutions.', '{"capacity_notes":"Powder Bed Fusion (SLS, MJF, SLM/DMLS) up to 400x400x400 mm, for up to 3000 parts. Material Extrusion (FDM/FFF) up to 1000x1000x1000 mm, for up to 500 parts. VAT Photo-polymerization (LCD, DLP, SLA) up to 300x300x300 mm, for up to 500 parts. Direct Energy Deposition (Wire DED, Powder DED) for up to 100 parts. Binder Jetting for up to 3000 parts. They also offer post-processing services including mechanical, thermal, and chemical treatments, and coatings.","certifications":[],"industries_served":["Mechanical Engineering","Manufacturing","Metallurgy","Research & Development","Medical Technologies","Food & Beverage Industry","Energy & Fuels","Automotive & Transport","Dental Medicine","Electronics","Defense"],"overview":"HabitAdd OOD is a Bulgarian company specializing in engineering, consulting, and manufacturing services within additive manufacturing technologies, also known as 3D Printing. They offer a comprehensive approach to engineering and production solutions for various industries, aiming to optimize processes and products through their network of partners. Their services are built on providing specific engineering know-how in the application and development of 3D printing solutions.","unique_value":"HabitAdd offers a broad range of additive manufacturing technologies including metal and polymer printing, coupled with extensive engineering, 3D scanning, and post-processing services. They provide rapid production times (1-4 days) and cater to both prototyping and small to medium-batch production, emphasizing functional parts, complex geometries, and on-demand manufacturing of spare parts."}', '{}'::jsonb, NULL, '1-4 days production, next day delivery in EU', false, true, '{}', '639b54fb-f5aa-4c62-a77d-a6e7c8314649', '2026-02-06 09:00:28.799+00', 92, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('103247e7-ac5f-4097-879f-b13779fbdc68', 'shapeways', 'Shapeways', 'https://www.shapeways.com/', 'Eindhoven, The Netherlands', 'Eindhoven', 'Netherlands', 51.43773, 5.480267, ARRAY['mjf','sls','binder-jetting','sla','metal-3d-printing','fdm'], ARRAY['nylon-12','resin','stainless-steel-316l','steel-infused-with-bronze','powders','photopolymers','abs','asa','polycarbonate','pet','petg'], NULL, NULL, NULL, true, false, 0, 0, 'Shapeways is a turnkey digital manufacturing partner specializing in design optimization, prototyping, and production of next-gen hardware. They offer a wide range of additive manufacturing technologies including MJF, SLS, Binder Jetting, and SLA, utilizing materials like Nylon 12, various resins, and Stainless Steel. Shapeways serves industries such as robotics, drones, medtech, electronics, and defense, providing scalable solutions from single parts to high-volume production.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '2af56425-bb25-4ce2-8c4a-f6aef6217ed3', '2026-01-20 07:00:55.752+00', 0, 1, '2025-11-11 14:58:48.660984+00', '2026-03-23 14:39:50.909845+00') ON CONFLICT (id) DO NOTHING;
