INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('53e0562f-9fd1-4358-b531-9d66ffce5690', 'norra-am', 'Norra AM', 'https://norraam.se', 'Hudiksvall, Sweden', 'Hudiksvall', 'Sweden', 61.7168708, 17.1005026, ARRAY['industrial-3d-printing','powder-bed-fusion','sls','mjf'], ARRAY['nylon-(pa)'], NULL, 'free-listing', 'europe', true, false, 0, 0, 'Norra AM specializes in on-demand industrial 3D printing services, leveraging advanced additive manufacturing technologies like Powder Bed Fusion to produce end-use parts and prototypes. Based in Hudiksvall, Sweden, the company offers fast, easy online quoting and aims to streamline the manufacturing process for engineers and production departments.', NULL, '{"TechnologyID":["mjf","sla","sls","dlp","fdm","material-jetting"],"affiliatelinkid":"https://norraam.se","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"Håstaholmen 5, 824 44 Hudiksvall, Sweden","building":""},"thermoplasticid":["tpu-mjf","pa11-sls","pa-gf","pa-12-bluesint","pa-12","nylon-pa-12","nylon-12-mineral-filled-hst","nylon-12-glass-bead-filled-gf","nylon-12-flame-retardant-fr","nylon-12-aluminum-filled-af","nylon-12","pa-12-carbon-filled","nylon-pa-12-blue-metal","sls_pa12_pa2200","mjf_pa12","sls_flexible_tpu"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', '07caee3e-3497-4743-b70b-1e46bcaba55b', '2026-01-19 19:00:55.216+00', 0, 0, '2025-10-23 16:57:29.437565+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
