INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('a2db2f45-ae99-4720-9418-014c9a2d6d39', 'oerlikon-am', 'Oerlikon AM', 'https://www.oerlikon.com', 'Pfäffikon SZ, Switzerland', 'Garching bei München', 'Germany', 47.201427, 8.777725, ARRAY['additive-manufacturing','thermal-spray'], ARRAY['nickel-alloys','cobalt-alloys','titanium','tool-steels','stainless-steel'], NULL, NULL, 'europe', true, false, 0, 0, 'Oerlikon AM is the additive manufacturing business unit of OC Oerlikon. Headquartered in Garching bei München, Germany (Oerlikon Group HQ remains in Pfäffikon, Switzerland). Oerlikon AM offers metal additive manufacturing services, metal powders, and advanced surface treatments for aerospace, defense, and semiconductor industries.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'e20d3512-5d23-47cf-acf3-1438ebdd7538', '2026-01-22 06:00:47.6+00', 0, 2, '2025-11-11 15:35:20.084757+00', '2026-03-16 08:11:34.894075+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('d85992a8-c5c0-4a86-a4bb-de474579d21b', 'treatstock-wenext', 'Wenext Technology Co., Ltd', 'https://www.wenext.com', 'Shenzhen City, Guang Dong Province, China', 'Shenzhen City', 'China', 22.5445741, 114.0545429, ARRAY['slm','fdm','sla','mjf','sls','vacuum-casting'], ARRAY['aluminum','stainless-steel','tool-steel','resin','nylon','polypropylene','abs','asa','copper','steel','pc','pom','acrylic','pa','pp','tpu','titanium'], NULL, NULL, NULL, true, false, 0, 0, 'Wenext is a leading manufacturing service bureau providing on-demand services including 3D Printing, CNC machining, sheet metal fabrication, and injection molding. They leverage an online instant quoting engine, self-developed supply chain management systems, and extensive in-house production capabilities to fulfill diverse manufacturing needs. Their mission is to accelerate global supply chain innovation through digital manufacturing.', '{"capacity_notes":"Wenext operates over 800 machines for 3D printing and 400+ machines for CNC machining, shipping over 80,000 machined parts monthly. They also have 20+ injection molding machines (80T to 600T). Standard lead time for SLS, MJF, and SLA is 48/72 hours, and 4 business days for CNC machining.","certifications":["ISO 9001","ISO 45001"],"industries_served":["Automotive","Art and Design"],"overview":"Wenext is a leading manufacturing service bureau providing on-demand services including 3D Printing, CNC machining, sheet metal fabrication, and injection molding. They leverage an online instant quoting engine, self-developed supply chain management systems, and extensive in-house production capabilities to fulfill diverse manufacturing needs. Their mission is to accelerate global supply chain innovation through digital manufacturing.","unique_value":"Wenext distinguishes itself with an online instant quoting system and a self-developed supply chain management system, supported by massive in-house production facilities. They offer a wide range of manufacturing processes from prototyping to mass production with no minimum order quantity, and boast a high on-time performance of 99.2% and a defect rate of less than 0.1%."}', '{}'::jsonb, NULL, '48-72 hours (3D printing), 4 business days (CNC)', false, true, '{}', '70ad71f3-c876-44f0-8cb6-d25f2c271283', '2026-02-05 13:01:51.043+00', 98, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
