INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('e9e23c3c-eb42-4188-b4b6-cb2ca086b01c', 'treatstock-nanofract', 'NanoFract UG', 'https://www.nanofract.com', 'Magdeburg, Germany', 'Magdeburg', 'Germany', 52.1314783, 11.6400789, ARRAY['fdm'], ARRAY['plastic','metal','ceramic','stainless-steel','tool-steel','aluminum','brass','glass-fiber'], NULL, NULL, NULL, true, false, 0, 0, 'NanoFract, a spin-off from Otto von Guericke University Magdeburg, specializes in powder technologies, material optimization, and FEM calculations. The company focuses on developing new composite materials through innovative nano and micro-level coating technologies for various applications. They offer services ranging from powder modification and granular coating to filament extrusion and 3D printing of prototype parts.', '{"capacity_notes":"Offers 3D printing services up to 200 x 200 x 200 mm, capable of processing high-temperature plastics (up to 450°C). They also extrude modified plastics and metallic FDM filaments.","certifications":[],"industries_served":[],"overview":"NanoFract, a spin-off from Otto von Guericke University Magdeburg, specializes in powder technologies, material optimization, and FEM calculations. The company focuses on developing new composite materials through innovative nano and micro-level coating technologies for various applications. They offer services ranging from powder modification and granular coating to filament extrusion and 3D printing of prototype parts.","unique_value":"NanoFract''s core strength lies in its innovative nano and micro-level coating technology for various materials (plastic, metal, ceramics), enabling the development of new composite materials with enhanced properties. They also specialize in producing micro and nano powders and offer extrusion of metallic FDM filament."}', '{}'::jsonb, NULL, NULL, false, false, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-02-06 10:01:17.584+00', 93, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('f115bb46-26d8-4823-8b1e-1f43452e084c', 'treatstock-plus-manufact', 'Plus Manufact GmbH', 'https://plusmanufact.de', 'Jagstzell, Germany', 'Jagstzell', 'Germany', 48.8375607, 10.0929593, ARRAY['mjf','slm'], ARRAY['aluminum','steel','titanium'], NULL, NULL, NULL, true, false, 0, 0, 'Plus Manufact GmbH specializes in high-quality 3D printing services, offering cost-effective and time-saving solutions for various industries. They leverage Multi Jet Fusion (MJF) and Selective Laser Melting (SLM) technologies to produce precise prototypes and functional parts. The company focuses on optimizing processes, reducing lead times, and enhancing product functionality for its clients.', '{"capacity_notes":null,"certifications":[],"industries_served":["Mechanical Engineering","Electronics Industry","Orthotics","Model Making","Automotive"],"overview":"Plus Manufact GmbH specializes in high-quality 3D printing services, offering cost-effective and time-saving solutions for various industries. They leverage Multi Jet Fusion (MJF) and Selective Laser Melting (SLM) technologies to produce precise prototypes and functional parts. The company focuses on optimizing processes, reducing lead times, and enhancing product functionality for its clients.","unique_value":"Plus Manufact offers rapid part procurement with a typical lead time of 48 hours, significantly reducing development and product launch times. They provide comprehensive services from consultation and design optimization using modern CAD software and topology optimization tools, to post-processing and reverse engineering for existing parts."}', '{}'::jsonb, NULL, '48 hours', true, true, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-02-05 13:01:45.854+00', 97, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('5591f74f-f757-4c65-b190-7be2d0c77294', 'treatstock-3dr-tech', '3DR TECH', 'http://3drtech.it', NULL, 'Prata di Pordenone', 'Italy', 45.8727176, 12.5852578, ARRAY['fdm'], ARRAY['pla','petg','abs','tpu','carbon-fiber','glass-fiber'], NULL, NULL, NULL, true, false, 0, 0, '3DR Tech is an Italian company specializing in professional 3D printing solutions, transforming ideas into tangible realities. They offer advanced technology, precision, and customization for functional and aesthetic prototypes, furnishing accessories, and custom productions. Their mission is to deliver high-quality, Made in Italy products.', '{"capacity_notes":null,"certifications":[],"industries_served":[],"overview":"3DR Tech is an Italian company specializing in professional 3D printing solutions, transforming ideas into tangible realities. They offer advanced technology, precision, and customization for functional and aesthetic prototypes, furnishing accessories, and custom productions. Their mission is to deliver high-quality, Made in Italy products.","unique_value":"3DR Tech provides comprehensive support from CAD design to 3D printing, offering both unique pieces and series production. They emphasize reduced lead times and optimized logistics, alongside personalized consultation to guide clients from concept to final product."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'd0e9b464-0c14-48c5-a7e6-4c2d4a421ba4', '2026-02-05 13:04:25.617+00', 67, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT 