ea."}', '{}'::jsonb, NULL, NULL, false, true, '{}', '70ad71f3-c876-44f0-8cb6-d25f2c271283', '2026-02-05 13:06:28.136+00', 17, 2, '2025-11-11 15:08:51.871431+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
