INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('861cbc58-c0a0-4d60-9fd7-c5a7d8793b66', '3t-additive-manufacturing', '3T Additive Manufacturing', 'https://www.3t-am.com', 'UK', NULL, 'United Kingdom', 51.4021554, -1.2963926, ARRAY['metal-3d-printing'], ARRAY['metal'], 'white', 'free-listing', 'europe', true, false, 0, 0, '3T Additive Manufacturing is a UK-based supplier specializing in advanced metal additive manufacturing. They provide finished metal components and sub-assemblies, offering services from design optimization and early development to series production. The company serves various industries including energy, industrial equipment, aerospace, space, and defense.', NULL, '{"TechnologyID":["dmls","sls"],"affiliatelinkid":"https://www.3t-am.com","cardStyle":"white","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"101 Warehouse Rd, Thatcham RG19 6HN, UK","building":""},"metalid":["aluminum-aisi10mg","titanium-ti-6al-4v","steel","stainless-steel-316l","stainless-steel-17-4ph","inconel-718","inconel-625","ni625","maraging-steel"],"thermoplasticid":["nylon-12","sls_pa12_pa2200"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', '22e6185a-55ce-402e-8cf0-aef86374efae', '2026-01-19 16:00:51.663+00', 0, 1, '2025-10-23 16:57:27.145023+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('812a97b5-2db5-4b51-88c0-e3f0d8d4ff07', '3diligent', '3Diligent', 'https://www.3diligent.com', 'Dana Point, United States', 'Dana Point', 'United States', 33.473679, -117.696744, ARRAY['fdm','sla','sls','mjf','dlp','dmls','slm','ebm','material-jetting','binder-jetting'], ARRAY['metal','plastic','urethane','silicone'], NULL, NULL, NULL, true, false, 0, 0, 'Trustbridge connects design engineers, buyers, and suppliers on a single managed platform, offering integrated design, sourcing, and on-demand manufacturing services. They provide DFM feedback, prototyping, and access to a vetted global supply chain, bridging the gap between concept and commercial production. The company, founded by Cullen Hilkene (formerly of 3Diligent), aims to simplify supplier discovery and accelerate product development efficiently and at scale.', '{"capacity_notes":"Trustbridge leverages a global network of manufacturing partners, including CNC shops, to fulfill production needs. They focus on connecting clients with suppliers that match their capabilities and capacity.","certifications":["ISO Certified"],"industries_served":[],"overview":"Trustbridge connects design engineers, buyers, and suppliers on a single managed platform, offering integrated design, sourcing, and on-demand manufacturing services. They provide DFM feedback, prototyping, and access to a vetted global supply chain, bridging the gap between concept and commercial production. The company, founded by Cullen Hilkene (formerly of 3Diligent), aims to simplify supplier discovery and accelerate product development efficiently and at scale.","unique_value":"Trustbridge offers a unique integrated platform for design, sourcing, and on-demand manufacturing, providing critical Design for Manufacturability (DFM) analysis and managed procurement through a vetted global supplier network. They act as a manufacturing partner, offering qualified leads to shops without subscription fees, and provide instant, data-driven quoting for project owners."}', '{}'::jsonb, NULL, NULL, false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:03:39.928+00', 70, 2, '2025-11-11 15:08:51.871431+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
