INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('189899a2-01aa-4eef-915a-2cbc7d4e4373', 'ricoh-3d', 'Ricoh 3D', 'https://3d.ricoh.com/', 'UK', NULL, 'United Kingdom', 52.692808, -2.524536, ARRAY['metal-3d-printing','additive-manufacturing'], ARRAY['polypropylene'], NULL, NULL, NULL, true, false, 0, 0, 'Ricoh 3D offers additive manufacturing solutions from prototype to mass production, leveraging Ricoh''s global innovation and manufacturing heritage. They provide online ordering for 3D printed prototypes and small series production, with a focus on material and technology development. The company operates a state-of-the-art factory in the UK and emphasizes sustainable manufacturing practices.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', '22e6185a-55ce-402e-8cf0-aef86374efae', '2026-01-20 06:01:04.227+00', 0, 1, '2025-11-11 14:58:48.660984+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('d67422ef-7779-49d0-a9e9-bdecfc0203c1', 'discovered-dd386427', '3DCeram', 'https://3dceram.com', 'Bonnac-La-Côte, France', 'Bonnac-La-Côte', 'France', 45.9414452, 1.2853534, ARRAY['sla','fdm'], ARRAY['ceramic','copper','stainless-steel'], NULL, NULL, NULL, true, false, 0, 0, '3DCeram is a turnkey provider for additive manufacturing ceramics, specializing in ceramic 3D printing solutions. The company offers a range of ceramic 3D printers, from R&D to industrial-scale production, alongside custom ceramic material formulations. With over 20 years of expertise, 3DCeram supports industries like aerospace, biomedical, and general manufacturing with high-performance ceramic parts.', '{"capacity_notes":"3DCeram offers a range of ceramic 3D printers from the C101 EASY LAB for development and prototyping, to the C1000 FLEXMATIC for semi-automatic industrial production, and the C3601 ULTIMATE for large parts. They also provide production-on-demand services using their Ceramaker machines.","certifications":[],"industries_served":["Aerospace","Defense","Electronics","Chemistry","Telecommunications","Biomedical","Medical Implants","Research","Foundry"],"overview":"3DCeram is a turnkey provider for additive manufacturing ceramics, specializing in ceramic 3D printing solutions. The company offers a range of ceramic 3D printers, from R&D to industrial-scale production, alongside custom ceramic material formulations. With over 20 years of expertise, 3DCeram supports industries like aerospace, biomedical, and general manufacturing with high-performance ceramic parts.","unique_value":"3DCeram specializes exclusively in ceramic additive manufacturing, offering proprietary 3DMIX ceramic slurries and a unique service for developing custom ceramic formulations. They provide a full range of ceramic 3D printers (C101 EASY LAB, C1000 FLEXMATIC, C3601 ULTIMATE) and advanced extrusion systems for technical ceramics, copper, and stainless steel, catering to both R&D and serial production."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'e1f5c58c-c518-4525-92f7-de100c711be1', '2026-02-06 02:00:50.329+00', 95, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('e2eddc62-8458-4efb-a393-8bd82a47b5f6', 'additive-tectonics-gmbh', 'additive tectonics GmbH', 'https://www.additive-tectonics.com', 'Am Grohberg 1, 92331 Lupburg, Germany', 'Lupburg', 'Germany', 49.1555658, 11.755624, ARRAY['concrete-3d-printing'], ARRAY['concrete'], NULL, NULL, NULL, true, false, 0, 0, 'additive tectonics GmbH develops architectural 3D printing for the future of construction. Using particle bed 3D printing (SCA/SPI), the company produces large, complex concrete components without formwork — from structural elements to ornamental facades — at scales up to 10 m³. Services span computational design, structural engineering, execution planning, in-house additive manufacturing, and prefabrication for art, architecture, and design clients.', '{"headquarters":"Am Grohberg 1, 92331 Lupburg, Germany","contact":{"email":"info@additive-tectonics.com","phone":"+49 (0) 9492 9429 200"},"leadership":{"managing_directors":["Carl Fruth","Bruno Knychalla"]},"registration":{"court":"Amtsgericht Nürnberg","hrb":"HRB 38032","vat_id":"DE335826920"},"capacity_notes":"Particle bed 3D printing (SCA/SPI) — parts up to 10 m³ printed in under 5 hours. Gantry-based and robotic-arm systems used for printing, milling, part handling, and hybrid operations. BIM/CAD-to-production workflow developed with Autodesk; AI-driven real-time quality prediction.","services":["Computational design","Execution planning","Structural engineering","In-house additive manufacturing","Installation and prefabrication","Product development (prototype to serial production)"],"materials_offered":{"tectonitX":"standard concrete, 3D-printed directly from the digital model","econitWood":"composite material from sawmill scraps and timber harvesting leftovers","additional":["metals","ceramics","recycled aggregates","custom experimental mixes"]},"compliance":"Qualified manufacturer under European Construction Products Regulation (CPR); CE marking and performance declarations; Eurocode and local structural code compliance.","industries":["Architecture","Construction","Art","Design"]}', '{}'::jsonb, NULL, NULL, false, false, ARRAY['CE Marking']::text[], '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-04-26 15:00:00+00', 100, 0, '2025-10-25 16:41:25.326792+00', '2026-04-26 15:00:00+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('1a1a4483-28cd-4afc-87f3-18960206b4a2', 'discovered-db080866', 'Fixie 3D', 'https://fixie3d.com', 'London, United Kingdom', 'London', 'United Kingdom', 51.5074456, -0.1277653, ARRAY['sla'], ARRAY['resin'], NULL, NULL, NULL, true, false, 0, 0, 'Fixie 3D provides expert 3D printing services specializing in architectural model making in London. With over 15 years of experience, the company focuses on creating high-quality, detailed, and scalable models for client presentations, design refinement, and competitions. They utilize advanced laser stereolithography (SLA) technology to ensure smooth finishes and precise representation of architectural designs.', '{"capacity_notes":"Operates a fleet of various sized 3D printers, including large-format printers with a build size of 750 x 750 x 550 mm.","certifications":[],"industries_served":["Architecture"],"overview":"Fixie 3D provides expert 3D printing services specializing in architectural model making in London. With over 15 years of experience, the company focuses on creating high-quality, detailed, and scalable models for client presentations, design refinement, and competitions. They utilize advanced laser stereolithography (SLA) technology to ensure smooth finishes and precise representation of architectural designs.","unique_value":"Fixie 3D specializes exclusively in architectural 3D printing and model making, offering deep expertise in preparing 3D files for this niche. They provide large-format SLA printing with a build size of 750 x 750 x 550 mm and offer comprehensive finishing services including spray painting, assembly, animation, and mounting."}', '{}'::jsonb, NULL, NULL, true, false, '{}', '22e6185a-55ce-402e-8cf0-aef86374efae', '2026-02-04 20:00:39.135+00', 97, 0, '2026-02-02 11:27:37.061488+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
