INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('a3130701-f802-466b-b156-5addb0fe71c3', 'treatstock-baesstech', 'Baesstech-Engineering', 'https://www.baesstech-engineering.de', 'Germany', NULL, 'Germany', 49.3123993, 12.1938198, ARRAY['fdm'], ARRAY['petg'], NULL, NULL, NULL, true, false, 0, 0, 'Baesstech-Engineering is a German company specializing in innovative product development and additive manufacturing. They guide clients from initial product ideas through design, 3D printing, and even marketing strategies. The company offers a comprehensive service, including construction, 3D printing of prototypes and small series, and start-up support for successful market launch.', '{"capacity_notes":"The company offers 3D printing services for prototypes, unique pieces, and small series, indicating a flexible production capacity tailored to on-demand manufacturing.","certifications":[],"industries_served":[],"overview":"Baesstech-Engineering is a German company specializing in innovative product development and additive manufacturing. They guide clients from initial product ideas through design, 3D printing, and even marketing strategies. The company offers a comprehensive service, including construction, 3D printing of prototypes and small series, and start-up support for successful market launch.","unique_value":"Baesstech-Engineering offers an end-to-end service from product idea conception and 3D model creation to additive manufacturing and comprehensive start-up services, including brand naming, logo design, and marketing strategy consultation. They provide tailored service packages to support clients throughout the entire product development and market launch process."}', '{}'::jsonb, NULL, NULL, false, true, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-02-05 13:02:59.023+00', 80, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('177c9653-38d4-49f0-8d22-1a2b3437bda4', 'incodema3d', 'Incodema3D', 'https://www.incodema3d.com', 'Freeville, NY, USA', 'Freeville', 'United States', 42.4981354, -76.3700898, ARRAY['metal-3d-printing','lpbf','cnc-machining'], ARRAY['metal'], 'white', 'free-listing', 'northamerica', true, false, 0, 0, 'Incodema3D specializes in additive metal production, focusing on direct metal 3D printing and LPBF technology. They offer comprehensive contract manufacturing services, including CNC machining, quality control, and program management. The company primarily serves the aerospace, defense, and other industrial sectors.', NULL, '{"TechnologyID":["dmls"],"affiliatelinkid":"https://www.incodema3d.com","cardStyle":"white","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"Ithaca, NY, USA","building":""},"metalid":["maraging-steel","aluminum-aisi10mg","titanium-ti-6al-4v","steel","stainless-steel-316l","stainless-steel-17-4ph","inconel-718","inconel-625","ni625"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-19 13:00:57.439+00', 0, 1, '2025-10-23 16:57:26.701329+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('2b0fe47e-41ff-42f7-9fee-1fbab70cd01d', 'arcreo', 'ARCreo', 'https://arcreo.it', 'Via Gaetano Salvemini, 16/18, 41123 Modena (MO), Italy', 'Modena', 'Italy', 44.6534553, 10.8804476, ARRAY['waam'], ARRAY['steel'], NULL, NULL, NULL, true, false, 0, 0, 'ARCreo is a metal additive-manufacturing brand based in Modena, Italy, operated by Guidetti Technology S.r.l. (Società Unipersonale) — a spin-off of the Arroweld Italia S.p.A. group dedicated to additive manufacturing. ARCreo''s proprietary "ARCadditive" technology is a wire-arc additive process (WAAM) that melts a wire with an electric arc and deposits it layer-by-layer to build metal parts, using Fronius TPSi 400 CMT and iWAVE 400 Pro Additive welding generators. The product range includes the Weld3X (3-axis printer, Ø500 × 800 mm build volume) and the Weld6X (6-axis collaborative robot, 1300 or 1900 mm reach), plus a conversion service that turns an existing welder into a 3D printer. ARCreo also runs an in-house 3D-printing service from its demo room in Modena, producing high-quality samples, small / limited-edition batches, and on-demand parts in metal alloys, with a free 30-minute consultation available on request. Quotes are form-based (no live quoting tool). Headquartered at Via Gaetano Salvemini, 16/18, 41123 Modena (MO), Italy. Phone +39 059 314353, email info@arcreo.it.', '{"overview":"ARCreo is a Modena-based metal additive-manufacturing brand operated by Guidetti Technology S.r.l. (Società Unipersonale), a spin-off of the Arroweld Italia S.p.A. group dedicated to additive manufacturing.","unique_value":"Proprietary WAAM technology (\"ARCadditive\") productised into Weld3X (3-axis) and Weld6X (6-axis collaborative robot) printers, plus an in-house metal 3D-printing service and a welder-to-3D-printer conversion service.","parent_company":{"legal_entity":"Guidetti Technology S.r.l. — Società Unipersonale","group":"Arroweld Italia S.p.A.","history":"Guidetti was founded in Modena in 1971; joined the Arroweld Italia group in 2009; ARCreo is a spin-off dedicated to additive manufacturing."},"headquarters":"Via Gaetano Salvemini, 16/18, 41123 Modena (MO), Italy","contact":{"phone":"+39 059 314353","email":"info@arcreo.it","email_brochure":"arcreo@arroweld.com","website":"https://arcreo.it","consultation":"Free 30-minute consultation on request"},"technology":{"name":"ARCadditive","process":"WAAM (Wire Arc Additive Manufacturing) — wire melted by an electric arc, deposited layer-by-layer","welding_generators":["Fronius TPSi 400 CMT","Fronius iWAVE 400 Pro Additive"]},"products":[{"name":"Weld3X","type":"3-axis metal 3D printer","build_volume":"Ø500 × h800 mm","external_size":"Ø1200 × h1800 mm","weight_kg":380,"deposit_rate":"1–4 kg/h","layer_height":"0.8–2 mm","bead_width":"2.5–10 mm"},{"name":"Weld6X","type":"6-axis collaborative-robot metal 3D printer","robot_reach":"1300 or 1900 mm","footprint_1300":"1400 × 2600 × h2150 mm","footprint_1900":"1700 × 3200 × h2150 mm","weight_kg":"730 / 1020","deposit_rate":"1–4 kg/h","layer_height":"0.8–2 mm","bead_width":"2.5–10 mm"},{"name":"Welder-to-3D-printer conversion","type":"Service","description":"Convert an existing welding machine into a 3D printer using ARCreo technology."}],"services_offered":[{"name":"High-quality metal samples","description":"3D-printed samples in metal alloys produced in the Modena demo room."},{"name":"Small / limited-edition batches","description":"Small production runs, limited editions, and on-demand supply."},{"name":"Project validation & market testing","description":"Helps customers validate projects, test the market early, and attract new customers."}],"features":["Reduced lead times — parts available on-demand from the demo room","Reduced material waste — layer-by-layer deposition","Design freedom — complex geometries impossible with traditional methods","On-demand production — no need for large stock","Integration with CNC, forging and casting workflows","Reduced environmental impact vs traditional manufacturing","Repair of existing metal components"],"industries_served":[],"instant_quote_url":null,"has_rush_service":false,"verified_sources":[{"url":"https://arcreo.it/","used_for":"Brand, product overview, advantages"},{"url":"https://arcreo.it/en/chi-siamo","used_for":"Parent company (Guidetti Technology / Arroweld Italia), Modena origin"},{"url":"https://arcreo.it/en/prodotti","used_for":"Weld3X / Weld6X technical specifications, Fronius generators"},{"url":"https://arcreo.it/en/servizi","used_for":"In-house 3D-printing service, demo room in Modena"},{"url":"https://arcreo.it/en/guida","used_for":"ARCadditive technology description (wire arc additive)"},{"url":"https://arcreo.it/en/contatti","used_for":"HQ address, phone, email, Google Maps coordinates"},{"url":"https://arcreo.it/wp-content/uploads/2025/11/ARCreo_Brochure_ENG.pdf","used_for":"English brochure: address, \"100% metal alloys\", free 30-min consultation"}]}'::jsonb, '{"location": {"address": "Via Gaetano Salvemini, 16/18, 41123 Modena (MO), Italy"}}'::jsonb, NULL, NULL, false, false, '{}', 'd0e9b464-0c14-48c5-a7e6-4c2d4a421ba4', '2026-04-27 18:00:00+00', 100, 0, '2025-10-25 16:41:25.326792+00', '2026-04-27 18:00:00+00') ON CONFLICT (id) DO NOTHING;
