INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('9b3402f3-feb1-4ce2-b421-053871aaefa5', 'discovered-0a742dbb', 'Additive Manufacturing, LLC', 'https://additivemanufacturingllc.com', 'Lake Forest, California, United States', 'Lake Forest', 'United States', 36.1674263, -115.1484131, ARRAY['dmls','sls','fdm','sla'], ARRAY['metals','nylon','abs','plastics','ceramics','ceramic'], NULL, NULL, NULL, true, false, 0, 0, 'Full-service additive manufacturing provider offering DMLS, SLS, FDM, and SLA technologies. Locations in Lake Forest, CA and Las Vegas, NV.', '{"capacity_notes":"Offers short to mid-run manufacturing for up to 500 parts and assemblies. Leverages on-demand digital factories and a worldwide network of manufacturers to ensure no capacity constraints and dependable lead times for diverse plastic and metal materials.","certifications":["ISO 9001","ITAR"],"industries_served":["Aerospace","Medical Devices","Automotive","Consumer Electronics","Defense","Energy"],"overview":"Additive Manufacturing LLC is a US-based company with over 100 years of combined manufacturing experience, committed to providing unparalleled customer service and expert guidance in part design and production. They offer comprehensive metal and plastic prototyping and manufacturing solutions, bridging innovative additive technologies with conventional production methods. Their mission is to deliver high-quality components efficiently and competitively.","unique_value":"Additive Manufacturing LLC leverages over a century of combined manufacturing experience, offering a comprehensive spectrum of metal and plastic prototyping and short-to-mid-run manufacturing capabilities. They provide expert guidance to bridge innovative additive technologies with conventional production methods, ensuring agile, high-quality solutions and dependable lead times through a global network of manufacturers."}', '{}'::jsonb, NULL, 'Not specified', false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-06 08:01:21.918+00', 95, 0, '2026-02-02 12:22:49.614381+00', '2026-03-18 08:14:11.071738+00') ON CONFLICT (id) DO NOTHING;
