INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('bb8fbaf7-93fc-4776-b355-ad5bafc76b77', '3rd-dimension-additive-manufacturing', '3rd Dimension Additive Manufacturing', 'https://www.3daddmanufacturing.com', 'Augusta, GA, United States', 'Augusta', 'United States', 33.46502, -81.95974, ARRAY['3d-printing'], ARRAY['carbon-fiber'], NULL, NULL, NULL, true, false, 0, 0, '3rd Dimension Additive Manufacturing, founded in 2021 by Matt Anderson and Troy Flugaur in Augusta, GA, specializes in providing rapid 3D printed solutions. The company aims to bridge the gap in manufacturing and engineering by offering industrial fabrication methods for prototypes and functional parts. They focus on accelerating product development and delivering machine-ready, fiber-reinforced components.', '{"capacity_notes":"Capable of producing fiber-reinforced parts and offers material selection for strength, flexibility, wear resistance, low friction coefficients, and electrical conductivity/insulation.","certifications":[],"industries_served":[],"overview":"3rd Dimension Additive Manufacturing, founded in 2021 by Matt Anderson and Troy Flugaur in Augusta, GA, specializes in providing rapid 3D printed solutions. The company aims to bridge the gap in manufacturing and engineering by offering industrial fabrication methods for prototypes and functional parts. They focus on accelerating product development and delivering machine-ready, fiber-reinforced components.","unique_value":"The company emphasizes its ability to produce machine-ready, fiber-reinforced parts, transforming 3D printing from a hobbyist activity into an industrial fabrication method. They also offer mechanical CAD services to help turn ideas into 3D models and prototypes."}', '{}'::jsonb, NULL, 'days/hours', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:04:20.515+00', 78, 1, '2025-11-11 15:59:48.061666+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('cd2c8020-74f3-4dc7-8849-64d793f0abd3', '3dspro', '3DSPRO', 'https://3dspro.com/', 'Room 602, 6/F, Kai Yue Commercial Building, 2C Argyle Street, Mongkok, Kowloon', 'Hong Kong', 'Hong Kong', 22.31755, 114.16927, ARRAY['slm','sls','mjf','sla','lcd','dlp'], ARRAY['aluminum-alsi10mg','aluminum-6061','inconel-718','ss-316l','ss-17-4ph','maraging-steel','titanium-ti6al4v','pa12','pa11','pa6','glass-filled-nylon','carbon-filled-nylon','tpu','polypropylene','standard-resin','tough-resin','flexible-resin','high-temp-resin','clear-resin','castable-resin','dental-resin','biocompatible-resin'], NULL, NULL, NULL, true, false, 0, 0, '3DSPRO is a 3D printing service provider dedicated to accelerating innovation by offering a comprehensive range of additive manufacturing solutions. They provide a one-stop service covering various quality and quantity requirements throughout the product development lifecycle. The company focuses on delivering efficient solutions with competitive pricing, aiming to reduce overall costs and time to market for their clients.', '{"capacity_notes":"3DSPRO operates 100+ industrial printers across 6 printing technologies (SLM, SLS, MJF, SLA, LCD, DLP) and offers 20+ resin materials alongside metals, nylons, TPU and polypropylene.","certifications":["ISO 9001"],"industries_served":["Art & Design","Robotics","Automotive","Consumer Goods","Aerospace","Agriculture","Energy","Medical"],"overview":"3DSPRO is a 3D printing service provider dedicated to accelerating innovation by offering a comprehensive range of additive manufacturing solutions. They provide a one-stop service covering various quality and quantity requirements throughout the product development lifecycle. The company focuses on delivering efficient solutions with competitive pricing, aiming to reduce overall costs and time to market for their clients.","unique_value":"3DSPRO emphasizes a ''Lowest General Cost'' approach, focusing on saving clients money and time across the entire product development journey, not just production costs. They integrate 3D printing services with ''3D+ solutions'' and offer an ''End-to-End Guarantee'' with fast response times and speedy delivery. They also prioritize intellectual property protection with a ''Safety Vault'' for designs.","headquarters":"Room 602, 6/F, Kai Yue Commercial Building, 2C Argyle Street, Mongkok, Kowloon, Hong Kong","contact":{"email":"SUCCESS@3DSPRO.COM","phone":"+852 6747 5414","whatsapp":"+86 13612668507"}}', '{}'::jsonb, NULL, NULL, false, true, ARRAY['ISO 9001']::text[], 'e8f3a7c1-b94d-4a2e-8c5b-1f6d3a9e7b2c', '2026-04-26 14:00:00+00', 100, 0, '2025-11-11 14:58:48.660984+00', '2026-04-26 14:00:00+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('af31de7a-055a-4ede-9ee1-6e88566d3d5b', 'discovered-ml53jiw0-gxwa', 'SOLIZE PARTNERS', 'https://partners.solize.com', 'Yokohama, Kanagawa, Japan', 'Yokohama', 'Japan', 35.4503381, 139.6343802, ARRAY['mjf','dlp','sla','sls','fdm','dmls'], ARRAY['aluminum','stainless-steel','magnesium','nylon-pa-12','nylon-12-glass-filled','pa-11','resin','flexible','high-temp-resin','tough-resin','elastomer','polycarbonate','abs','pp','peek','pei','pps','ppsu'], NULL, NULL, NULL, true, false, 0, 0, 'SOLIZE PARTNERS is a pioneer in 3D printing in Japan, having introduced the technology over 35 years ago. They offer comprehensive digital manufacturing solutions, from design and prototyping to small-batch production. With a team of approximately 1,200 engineers, SOLIZE PARTNERS supports clients in various industries by leveraging advanced 3D printing and digital engineering expertise.', '{"capacity_notes":"Operates 42 3D printers across 6 different additive manufacturing technologies. Annually produces over 80,000 parts. Holds a large inventory of high-end 3D printers from brands like 3D Systems, HP, and Roboze. Employs approximately 1,200 engineers.","certifications":["RoHS","EU REACH","USP Class I-VI","UL 94","UL 746A"],"industries_served":["Automotive","Aerospace","Consumer Goods","Medical Devices","Industrial Machinery"],"overview":"SOLIZE PARTNERS is a pioneer in 3D printing in Japan, having introduced the technology over 35 years ago. They offer comprehensive digital manufacturing solutions, from design and prototyping to small-batch production. With a team of approximately 1,200 engineers, SOLIZE PARTNERS supports clients in various industries by leveraging advanced 3D printing and digital engineering expertise.","unique_value":"SOLIZE PARTNERS is recognized as the first company in Japan to utilize 3D printers for manufacturing, accumulating over 35 years of experience. They boast one of the largest inventories of high-end 3D printers in Japan, including HP Jet Fusion and Figure 4 systems, and produce over 80,000 parts annually. Their independence as a technology group allows for flexible, client-centric solutions."}', '{}'::jsonb, NULL, '3 business days', true, true, '{}', 'a8cdfbed-db91-414a-b190-3ab1dbd6c7ae', '2026-02-07 06:00:22.596+00', 93, 0, '2026-02-02 11:38:39.885238+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0561884d-3064-4047-89e4-98c1b8eda721', 'protocam', 'ProtoCAM', 'https://www.protocam.com', 'Allentown, PA, United States', 'Allentown', 'United States', 40.602245, -75.471776, ARRAY['additive-manufacturing','cnc-machining','sheet-metal','edm'], ARRAY['accura®-xtreme-white-200','somos®-evolve-128'], NULL, NULL, NULL, true, false, 0, 0, 'ProtoCAM has integrated into Prototek Digital Manufacturing, expanding its offerings beyond additive manufacturing to include CNC machining, Sheet Metal, and EDM. With over three decades of experience and state-of-the-art facilities across the United States, Prototek aims to provide innovative solutions and unparalleled quality in product development and manufacturing. The company emphasizes collaboration, agility, innovation, and quality in its services.', '{"capacity_notes":"Prototek operates state-of-the-art facilities across the United States and has over three decades of experience in digital manufacturing.","certifications":[],"industries_served":[],"overview":"ProtoCAM has integrated into Prototek Digital Manufacturing, expanding its offerings beyond additive manufacturing to include CNC machining, Sheet Metal, and EDM. With over three decades of experience and state-of-the-art facilities across the United States, Prototek aims to provide innovative solutions and unparalleled quality in product development and manufacturing. The company emphasizes collaboration, agility, innovation, and quality in its services.","unique_value":"As part of Prototek, the company now offers a broader range of manufacturing services beyond additive manufacturing, including CNC machining, Sheet Metal, and EDM, providing a more comprehensive solution for prototype and short-run production."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:05:06.536+00', 32, 2, '2025-11-11 14:58:48.660984+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('65ef6cd6-fc8e-4de0-a387-9c84c60beebc', 'discovered-ml53hw3k-hvrq', 'SINTX', 'https://sintx.com', 'Salt Lake City, Utah, United States', 'Salt Lake City', 'United States', 40.7596198, -111.886797, ARRAY['fdm','sla'], ARRAY['ceramic','silicon-carbide','alumina','zirconia','pei','nylon','carbon-fiber-nylon'], NULL, NULL, NULL, true, false, 0, 0, 'SINTX Technologies is a leading manufacturer of silicon nitride and other advanced ceramics, innovating with these materials since 1996. They specialize in transforming concepts into quality, printed parts, offering unparalleled support in ceramic 3D printing. SINTX focuses on creating strong, abrasion- and corrosion-resistant ceramic solids with inherent antibacterial and antiviral properties for extreme environments.', '{"capacity_notes":"SINTX operates a vertically integrated, 30,000 sq. ft. manufacturing facility, which is the only FDA-registered silicon nitride medical device manufacturing facility globally. They offer rapid prototyping and contract manufacturing services for ceramic components.","certifications":["ISO 13485","AS9100D","ISO 9001","ITAR Registered"],"industries_served":["Biomedical","Aerospace","Automotive","Energy","Medical Devices","Dental Implants","Spinal Implants","Craniomaxillofacial"],"overview":"SINTX Technologies is a leading manufacturer of silicon nitride and other advanced ceramics, innovating with these materials since 1996. They specialize in transforming concepts into quality, printed parts, offering unparalleled support in ceramic 3D printing. SINTX focuses on creating strong, abrasion- and corrosion-resistant ceramic solids with inherent antibacterial and antiviral properties for extreme environments.","unique_value":"SINTX is the only FDA-registered silicon nitride medical device manufacturing facility in the world, specializing in advanced ceramic-polymer composite 3D printing services. They offer proprietary materials like FLEX-SN PEEK filament for FFF and develop custom ceramic resin compositions, leveraging a lithography-based approach for rapid prototyping and shortened development cycles."}', '{}'::jsonb, NULL, 'Not specified', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-04 23:00:31.828+00', 95, 0, '2026-02-02 11:37:23.694157+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
