INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('ac554611-ca9d-46cf-8225-2c6cafd22ff2', 'discovered-5fe4207d', 'Foundry Lab', 'https://youtube.com', NULL, 'Fremont, California', 'United States', 37.5482697, -121.988571, ARRAY['Binder Jetting'], ARRAY['Ceramic','Metal'], NULL, NULL, NULL, false, false, 0, 0, 'The provided website is for YouTube, a global online video sharing and social media platform owned by Google. Its mission is to give everyone a voice and show them the world by enabling users to upload, view, rate, share, add to playlists, report, comment on videos, and subscribe to other users. It hosts a wide variety of user-generated and corporate media videos.', '{"capacity_notes":"YouTube hosts billions of videos and serves over 2 billion logged-in users monthly, making it the second most visited website globally. Its infrastructure supports massive content storage, streaming, and user interaction on a global scale.","certifications":[],"industries_served":["Media & Entertainment","Education","Marketing & Advertising","News & Journalism","Music Industry","Gaming"],"overview":"The provided website is for YouTube, a global online video sharing and social media platform owned by Google. Its mission is to give everyone a voice and show them the world by enabling users to upload, view, rate, share, add to playlists, report, comment on videos, and subscribe to other users. It hosts a wide variety of user-generated and corporate media videos.","unique_value":"YouTube is the world''s largest online video sharing platform, offering an unparalleled global reach for content creators and viewers. It features a vast library of videos across all genres, from educational content to entertainment, and provides tools for content creation, sharing, and community building."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-10 08:00:27.609+00', 0, 5, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('eeae8240-a8f2-4883-bb8b-6909d4024570', 'discovered-947395a8', 'Aspect Biosystems', 'https://aspectbiosystems.com', 'Vancouver, BC, Canada', 'Vancouver', 'Canada', 49.2608724, -123.113952, ARRAY['bioprinting'], ARRAY['biomaterials'], NULL, NULL, NULL, true, false, 0, 0, 'Aspect Biosystems is a Canadian biotechnology company pioneering the development of bioprinted tissue therapeutics. They utilize a full-stack platform integrating AI-powered bioprinting technology, computational design tools, therapeutic cells, and advanced biomaterials. Their mission is to create implantable tissues that replace, repair, or supplement biological functions, aiming to transform the treatment of various diseases.', '{"capacity_notes":"The company has grown its team to over 100 people and has raised over US$260M+ in capital, indicating significant operational scale and investment in their bioprinting and therapeutic development capabilities.","certifications":[],"industries_served":["Regenerative Medicine","Biotechnology","Pharmaceuticals","Medical Devices"],"overview":"Aspect Biosystems is a Canadian biotechnology company pioneering the development of bioprinted tissue therapeutics. They utilize a full-stack platform integrating AI-powered bioprinting technology, computational design tools, therapeutic cells, and advanced biomaterials. Their mission is to create implantable tissues that replace, repair, or supplement biological functions, aiming to transform the treatment of various diseases.","unique_value":"Aspect Biosystems'' unique value lies in its proprietary AI-powered bioprinting technology and full-stack tissue therapeutic platform. This platform integrates computational design, therapeutic cells, hypoimmune cell engineering, and advanced biomaterials to create biologically functional, immune-protective, and surgically implantable allogeneic tissue therapeutics."}', '{}'::jsonb, NULL, NULL, false, false, '{}', '714df434-bfec-4dc7-8071-15b684e92414', '2026-02-07 15:00:17.081+00', 95, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
