INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('73a2497c-9b02-4c1a-88a7-832c7906734b', 'treatstock-arinta', 'Arinta Engineering', 'https://www.arintaengineering.com', 'Sturtevant, Wisconsin, United States', 'Sturtevant', 'United States', 42.5846773, -87.8212263, ARRAY['fdm'], ARRAY['steel','stainless-steel','aluminum','mild-steel','acrylic','wood'], NULL, NULL, NULL, true, false, 0, 0, 'Arinta Engineering is a Racine, Wisconsin-based company specializing in new product development, engineering design, and metal fabrication. Their facility is equipped with advanced 3D printers, precision plasma cutters, and expert welding capabilities, enabling them to produce high-quality metal products. They cater to individuals, inventors, startups, and small businesses, focusing on low-volume, custom metal parts.', '{"capacity_notes":"Offers CNC plasma cutting, welding, CNC press brake forming, and small-batch manufacturing. Capable of cutting mild steel, stainless steel, aluminum, and sheet metal up to 1/2\" thick, and acrylic, Lexan, and wood up to 1/4\" thick.","certifications":[],"industries_served":["Product Development","Automotive","Medical Device","Consumer Goods","Industrial Equipment"],"overview":"Arinta Engineering is a Racine, Wisconsin-based company specializing in new product development, engineering design, and metal fabrication. Their facility is equipped with advanced 3D printers, precision plasma cutters, and expert welding capabilities, enabling them to produce high-quality metal products. They cater to individuals, inventors, startups, and small businesses, focusing on low-volume, custom metal parts.","unique_value":"Arinta Engineering specializes in low-volume, custom metal parts, serving individuals, inventors, startups, and small businesses that larger shops often overlook. They offer comprehensive services from design and simulation using Solidworks to functional prototyping and fabrication."}', '{}'::jsonb, NULL, NULL, false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:02:18.684+00', 93, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('4a476828-8352-4e30-be2f-4502fb53f52d', 'discovered-cf74abfb', 'B9Creations', 'https://b9c.com', '2828 Plant St, Suite 2, Rapid City, SD 57702', 'Rapid City', 'United States', 44.0806041, -103.228023, ARRAY['dlp'], ARRAY['resin'], NULL, NULL, NULL, true, false, 0, 0, 'B9Creations is a U.S.-based digital manufacturing company headquartered in Rapid City, South Dakota, that designs and manufactures DLP-based 3D printers, photopolymer resins, and software, plus a Parts-on-Demand contract manufacturing service. The B9 Core, B9 Core Med, B9 Dent, B9 Elite (micro) and B9 6 Series platforms — together with FAST(TM) printing technology — serve high-precision applications in aerospace and defense, medical and biomedical engineering, dental, jewelry, prototyping and manufacturing, microscale, education and research, and entertainment. Materials range from engineering-grade (Rugged Nylon-6, Robust ABS, ESD Rigid, Resilient Silicone) and casting (Yellow, Emerald, FastWax, Cherry, Red) to biocompatible ISO 10993 BioRes families (BioRes-Silicone, BioRes-Clear, BioRes-Micro Precision, BioWhite, BioRed), dental (Model, Keystone Gingival Mask, Keystone Surgical Guide, DENTCA Crown & Bridge), and specialty resins (ATARU Black for high-temperature RF, Radix Printable Dielectric, Loctite 3D 3843, Loctite 3D IND147, bioinks). Customers include Johnson & Johnson, Hasbro, Stuller, Medtronic and Procter & Gamble, with certified dealers in nearly 70 countries.', '{"overview":"B9Creations, LLC is a Rapid City, South Dakota-based digital-manufacturing company that designs, manufactures and supports DLP-based 3D printers, photopolymer resins, software and post-processing accessories, alongside a Parts-on-Demand contract manufacturing service. Its end-to-end additive-manufacturing solutions are deployed in nearly 70 countries via a certified dealer network.","unique_value":"Combines proprietary DLP hardware (B9 Core, Core Med, Dent, Elite Micro, 6 Series) with FAST(TM) printing technology, an in-house resin portfolio spanning engineering, casting, biocompatible ISO 10993, dental and specialty (RF dielectric, high-temperature) families, and the B9Captivate material-development software suite — plus a Parts-on-Demand service for customers that prefer to outsource production.","legal_entity":"B9Creations, LLC","founded_by":"Michael Joyce (founder & CTO)","headquarters":"2828 Plant St, Suite 2, Rapid City, SD 57702, United States","secondary_office":"Dallas, Texas, United States (expansion office, opened post-2019)","contact":{"phone_customer_service":"+1 (605) 716-3200","phone_sales":"+1 (605) 787-0652","email":"info@b9c.com","website":"https://b9c.com","shop":"https://shop.b9c.com"},"technology":{"process":"DLP (Digital Light Processing) photopolymer 3D printing","proprietary":"FAST(TM) printing technology","micro_resolution":"Down to 10 microns effective resolution on the B9 Elite Micro platform; 20 micron vertical wall thickness, 50-100 micron channel diameters in Elite Micro Onyx"},"products":[{"name":"B9 Core Series","type":"3D printer","description":"Production-ready DLP platforms engineered for accuracy, speed and reliability."},{"name":"B9 Core Med Series","type":"3D printer","description":"Medical-grade 3D printing for medical devices, anatomical models and surgical tools."},{"name":"B9 Dent Series","type":"3D printer","description":"Precision dental 3D printers for the dental laboratory and clinic."},{"name":"B9 Elite Series (Micro)","type":"3D printer","description":"Micro 3D printing for intricate geometries impossible to make any other way."},{"name":"B9 6 Series","type":"3D printer","description":"Larger-format DLP printing for production volumes and bigger parts."},{"name":"B9[X] Custom Solutions","type":"Service","description":"Custom hardware, software, materials and services tailored to an end-to-end customer workflow."},{"name":"Parts on Demand","type":"Service","description":"Contract manufacturing service producing parts on-demand from prelaunch to production."},{"name":"B9 Scan 350 / 500","type":"3D scanner","description":"3D scanning hardware (B9 Scan 350, B9 Scan 500) for jewellery, dental and reverse engineering."},{"name":"B9Create","type":"Software","description":"Slicer, support and orientation software for B9Creations printers."},{"name":"B9Captivate","type":"Software","description":"Material-development software suite for custom resin formulation."}],"materials":{"engineering":["Rugged - Nylon 6","Resilient - Silicone","Robust - ABS","ESD - Rigid"],"casting":["Emerald","Yellow","FastWax","Cherry","Red"],"design":["Precision Gray","HD Clear","HD Slate","Gray","Black"],"micro":["Elite Micro Onyx","Elite Micro Transparent","HD Slate (micro)","HD Clear (micro)"],"biocompatible_iso10993":["BioRes-Silicone","BioRes-Clear","BioRes - Micro Precision","BioWhite (Medical/Wearable)","BioRed (Medical/Wearable)"],"dental":["B9 Model","Keystone Gingival Mask","Keystone Surgical Guide","DENTCA Crown & Bridge"],"specialty":["ATARU(TM) Black (Nano Dimension, RF, >300C)","Radix Printable Dielectric","Loctite 3D 3843","Loctite 3D IND147","Bioinks"]},"services_offered":[{"name":"Parts on Demand","description":"On-demand contract manufacturing of resin parts, from prelaunch prototyping to production volumes."},{"name":"B9[X] Custom Solutions","description":"Bespoke combinations of hardware, software, materials and services for end-to-end customer workflows."},{"name":"Custom material development","description":"Customer-specific resin formulation via the B9Captivate software suite."},{"name":"Global dealer network","description":"Certified dealers and distributors in nearly 70 countries."}],"industries_served":["Aerospace & Defense","Biomedical Engineering & Research","Dental","Education & Research","Entertainment","Jewelry","Manufacturing","Medical","Microscale"],"features":["40+ million parts 3D printed across the installed base","Certified dealer network in ~70 countries","End-to-end additive manufacturing: hardware + software + materials + accessories + service","Patented DLP technology with FAST(TM) print acceleration","Material-development toolkit (B9Captivate) for custom resin formulation","Recognised on Deloitte Fast 500 (2019), Inc. 5000 (2020), Financial Times Americas fastest-growing (2021)"],"customers":["Johnson & Johnson","Hasbro","Stuller, Inc.","Medtronic","Procter & Gamble"],"instant_quote_url":null,"has_rush_service":false,"verified_sources":[{"url":"https://www.b9c.com/","used_for":"Brand, headline product line, applications, customer claim, dealer network"},{"url":"https://www.b9c.com/products","used_for":"Product list (Core, Core Med, Dent, Elite, 6 Series, B9[X] Custom, Parts on Demand, scanners, software)"},{"url":"https://www.b9c.com/products/materials","used_for":"Full materials catalogue across engineering / casting / biocompatible / dental / specialty / micro families"},{"url":"https://www.b9c.com/applications","used_for":"Industry applications (Aerospace & Defense, Biomedical, Dental, Education, Entertainment, Jewelry, Manufacturing, Medical, Microscale)"},{"url":"https://www.b9c.com/contact/contact-us","used_for":"HQ address (2828 Plant St, Suite 2, Rapid City, SD 57702), customer-service & sales phones, email"},{"url":"https://www.b9c.com/about/story","used_for":"Founder Michael Joyce, Rapid City SD HQ, Dallas TX expansion office, customer list, growth-list awards"}]}'::jsonb, '{"phone_customer_service":"+1 (605) 716-3200","phone_sales":"+1 (605) 787-0652","email":"info@b9c.com","founded_by":"Michael Joyce","legal_entity":"B9Creations, LLC","hq":"2828 Plant St, Suite 2, Rapid City, SD 57702","secondary_office":"Dallas, TX"}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-04-27 19:00:00+00', 100, 0, '2025-12-26 19:36:37.928002+00', '2026-04-27 19:00:00+00') ON CONFLICT (id) DO NOTHING;
