INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('e135f7fc-7354-4a19-bc4b-9ea14ffe0b74', 'discovered-0dfaf825', 'OriginLabs - Penn State', 'https://originlabs.psu.edu', 'State College, PA, USA', 'State College', 'United States', 40.7944504, -77.8616386, ARRAY['sla','sls','polyjet'], ARRAY['resin','standard-resin','clear-resin','tough-resin','flexible-resin','high-temp-resin','nylon-pa-11','tpu','stainless-steel-316l','elastomer','abs'], NULL, NULL, NULL, true, false, 0, 0, 'OriginLabs, part of Penn State, is a prototyping and fabrication space offering a range of services including additive manufacturing. They specialize in SLA, SLS, and PolyJet 3D printing, utilizing various resins, nylon, TPU, and stainless steel materials. The lab provides access to world-class equipment for students, faculty, and the public.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-24 14:01:02.918+00', 97, 0, '2025-12-26 19:42:07.667342+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('f6369f78-d0b4-4069-bab3-03a4a78e53b5', 'one-off-robotics', 'One Off Robotics', 'https://oneoffrobotics.com', 'Chattanooga, Tennessee, USA', 'Chattanooga', 'United States', 35.063557, -85.310265, ARRAY['waam','robotic-3d-printing','fgf'], ARRAY['stainless-steel','mild-steel','aluminum','inconel','titanium','thermoplastic','ceramic','cementitious'], NULL, NULL, NULL, true, false, 0, 0, 'One Off Robotics specializes in robotic metal and thermoplastic additive manufacturing systems. They offer both stationary and field-deployable manufacturing systems for demanding production environments.', NULL, '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-22 16:00:42.538+00', 0, 1, '2025-11-11 15:57:15.934661+00', '2026-03-17 08:16:30.536538+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('788b14d9-5ebc-4ba7-a68b-89c3d5fe8d1e', 'baker-industries', 'Baker Industries', 'https://www.bakerindustriesinc.com', '16936 Enterprise Drive, Macomb, MI 48044, USA', 'Macomb', 'United States', 42.6672218, -82.9540081, ARRAY['waam','cnc-machining'], ARRAY['metal'], NULL, NULL, NULL, true, false, 0, 0, 'Baker Industries, a Lincoln Electric Company, is an award-winning contract manufacturer headquartered in Macomb, Michigan, specializing in large-scale, low-volume production. Founded in 1992 and now operating across five plants totaling 250,000+ ft², they combine 3-, 4-, 5-, and 7-axis CNC machining, fabrication and welding, and proprietary Wire Arc Additive Manufacturing (WAAM) — printing metal parts up to 8 feet tall and over 5,000 lbs using SculptPrint OS path-planning software. AS9100D, ISO 9001:2015 and ISO 14001:2015 certified, ITAR registered and Nadcap (AC7130) accredited. Serves aerospace, defense, space, automotive, energy and heavy-equipment customers including Boeing, Lockheed Martin, Rocket Lab, GKN Aerospace, GM and Stellantis.', '{"overview":"Baker Industries is an award-winning contract manufacturer in Macomb, Michigan, owned by The Lincoln Electric Company since 2019. Founded in 1992 by brothers Kevin and Scott Baker, the company specializes in large-scale, low-volume production combining CNC machining, fabrication and welding, and proprietary Wire Arc Additive Manufacturing (WAAM).","unique_value":"Single-source large-scale, low-volume manufacturing partner that combines 3- to 7-axis CNC machining, fabrication / welding, and proprietary large-scale WAAM metal 3D printing (8 ft, 5,000+ lbs) — backed by AS9100D, ISO 9001/14001, Nadcap and ITAR.","founded":1992,"parent_company":{"legal_entity":"Baker Industries, Inc.","parent":"The Lincoln Electric Company","acquired":"2019","history":"Founded 1992 in Mt. Clemens, MI as Baker Duplicating; rebranded over time to Baker Machining & Mold Technologies (1998-2000), Baker Aerospace Tooling & Machining (2011), Baker 3D Solutions (2015), and Baker Industries (2016). Acquired by Lincoln Electric in 2019 to support its automation portfolio and metal 3D printing businesses."},"headquarters":"16936 Enterprise Drive, Macomb, MI 48044, USA","facilities":[{"plant":"Plant 1 (HQ)","address":"16936 Enterprise Drive, Macomb, MI 48044","sq_ft":65000,"function":"CNC Machining"},{"plant":"Plant 2","address":"50271 Corporate Drive, Macomb, MI 48044","sq_ft":45000,"function":"Fabrication and Welding"},{"plant":"Plant 3","address":"16931 Enterprise Drive, Macomb, MI 48044","sq_ft":55000,"function":"Assembly and Inspection"},{"plant":"Plant 4","address":"16725 Corporate Drive, Macomb, MI 48044","sq_ft":55000,"function":"Assembly and Inspection"},{"plant":"Plant 5","address":"16280 23 Mile Road, Macomb, MI 48044","sq_ft":31000,"function":"Robotics and R&D (opened April 2022)"}],"total_square_footage":"250,000+ ft² across 5 plants in Macomb, MI","operations":"Two 12-hour shifts, 5-7 days per week","contact":{"phone":"+1 (586) 286-4900","website":"https://www.bakerindustriesinc.com"},"capabilities":["Design and Engineering (Baker Design Group, est. 2012)","CNC Machining — 3-, 4-, 5- and 7-axis; metal, plastic and composite; large-scale, low-volume","Fabrication and Welding — 45,000 ft² Plant 2; AWS and ASME qualified","Large-Scale 3D Metal Printing — proprietary Wire Arc Additive Manufacturing (WAAM / GMAAM); also Laser Hot-Wire","Automation and Integration — automated arc welding, assembly line solutions","Assembly and Finishing — two 55,000 ft² facilities, 30-ton overhead cranes, in-house industrial spray booth","Quality Inspection and Testing — CMMs, laser trackers, 3D scanners","On-Site Installation — global"],"waam_specs":{"process":"Wire Arc Additive Manufacturing (WAAM / GMAAM)","software":"SculptPrint OS path-planning software","max_height":"8 ft (2.4 m)","max_weight":"5,000+ lbs (2,268+ kg)","materials":["Aluminum-Nickel-Bronze","Invar 36","Nickel Alloy 617","Nickel Alloy 625","Nickel Alloy 718","17-4 PH Stainless Steel","316LSi Stainless Steel","410NiMo Stainless Steel","High-Strength Low-Alloy Steel","Low-Carbon Steel"]},"industries_served":["Aerospace, Defense, and Space","Architecture, Design, and Art","Automotive and Transportation","Energy and Power Generation","Heavy Equipment and Industrial Machinery","Industrial Automation","Medical Equipment","Oil and Gas","Rail and Ground Transportation","Recreational Equipment and Boatbuilding","Semiconductors","Shipbuilding and Maritime"],"notable_customers":["Boeing Commercial Airplanes","Lockheed Martin Missiles & Fire Control","Rocket Lab","GKN Aerospace","United Launch Alliance","Sikorsky","GM","Stellantis","SpaceX (Preferred Supplier)"],"certifications":["ISO 9001:2015 (Quality Management)","AS9100D (Aviation, Space, Defense)","ISO 14001:2015 (Environmental Management)","Nadcap Measurement & Inspection (AC7130)","AWS Certified Welding Inspectors (CWI)","AWS Certified Welding Supervisors (CWS)","ITAR registered","D-U-N-S Number, SAM.gov UEI, CAGE Code (federal contracting)"],"awards":["Hermeus Supplier of the Year 2025","Blue Origin Top Honors Environmental + Top Supplier New Glenn","Aerospace & Defense Review — Company of the Year, CNC Machining (2022)","Modern Machine Shop Top Shops (2018)","Boeing Performance Excellence (6x)","Lockheed Martin Outstanding Small Business","GE Aerospace Top-Rated Supplier","SpaceX Preferred Supplier"],"instant_quote_url":null,"has_rush_service":false,"verified_sources":[{"url":"https://www.bakeri