INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('d6f0224b-66de-4c1a-85b2-c9643865d053', 'protolabs', 'Protolabs – Digital Manufacturing & Rapid Prototyping', 'https://www.protolabs.com/', 'Maple Plain, MN, USA', 'Maple Plain', 'United States', 45.013078, -93.663648, ARRAY['3d-printing','sla','sls','fdm','metal-3d-printing','hps-3d-printing'], ARRAY['plastic','elastomeric','silicone-rubber','metal','aluminum','stainless-steel','steel','brass','copper','ceramic-filled-photopolymer','tough-black-photopolymer'], NULL, 'free-listing', 'northamerica', true, false, 0, 0, 'Protolabs is a digital manufacturing service offering rapid prototyping and production across various technologies. They specialize in quick-turn parts using 3D printing (SLA, SLS, FDM, Metal), CNC machining, injection molding, and sheet metal fabrication. Protolabs serves industries like aerospace, automotive, consumer electronics, and medical.', NULL, '{"TechnologyID":["sls","material-jetting","mjf","sla","dmp","saf"],"affiliatelinkid":"https://www.protolabs.com/","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"5540 Pioneer Creek Dr, Maple Plain, MN 55359, USA","building":""},"thermoplasticid":["pa-12-carbon-filled","pa-12","nylon-pa-12","abs-white","abs-like-black"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-20 00:00:48.067+00', 0, 1, '2025-10-23 16:57:31.495351+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0c5f5869-43d5-4fef-97bf-9e3c8830ebc9', 'discovered-9115c08d', 'RAMLAB', 'https://ramlab.com', 'Rotterdam, Netherlands', 'Rotterdam', 'Netherlands', 51.9244424, 4.47775, ARRAY['waam'], ARRAY['titanium','titanium-ti-6al-4v','metal'], NULL, NULL, NULL, true, false, 0, 0, 'RAMLAB is a leading innovator in advanced repair and manufacturing of metal parts, specializing in Wire Arc Additive Manufacturing (WAAM). The company develops modular systems to automate the entire process from design to production, ensuring efficiency, precision, and ease of use. RAMLAB''s mission is to make high-quality metal repair and manufacturing accessible globally, leveraging deep material expertise and certified processes.', '{"capacity_notes":"RAMLAB focuses on enhancing off-the-shelf robotic welding systems with proprietary monitoring and control solutions, allowing for flexible use of various robot sizes, welding systems, manipulators, and tracks, including multi-robot collaboration. Systems are delivered within months and installed within days.","certifications":["ISO 9001"],"industries_served":[],"overview":"RAMLAB is a leading innovator in advanced repair and manufacturing of metal parts, specializing in Wire Arc Additive Manufacturing (WAAM). The company develops modular systems to automate the entire process from design to production, ensuring efficiency, precision, and ease of use. RAMLAB''s mission is to make high-quality metal repair and manufacturing accessible globally, leveraging deep material expertise and certified processes.","unique_value":"RAMLAB specializes in Wire Arc Additive Manufacturing (WAAM) for both manufacturing and repair of metal parts, including large structures. They developed the MaxQ system for automated metal part repair and 3D printing, which significantly reduces lead times and reliance on skilled labor, offering a rapid ROI. They achieved the world''s first 3D printed propeller and were recognized in the Guinness Book of World Records for the WAAMpeller."}', '{}'::jsonb, NULL, NULL, false, false, '{}', '2af56425-bb25-4ce2-8c4a-f6aef6217ed3', '2026-02-06 00:01:24.31+00', 95, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
