INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('9d983ea6-61e6-44ef-ae53-771045cf4b80', 'discovered-685b0e94', 'OK Foundry Company, Inc.', 'https://okfoundry.com', 'Richmond, Virginia, United States', 'Richmond', 'United States', 48.1019817, -123.3023768, ARRAY['Sand Casting (using 3D printed molds and cores)'], ARRAY['steel','iron'], NULL, NULL, NULL, true, false, 0, 0, 'OK Foundry Company, Inc. is a family-owned and operated jobbing foundry established in 1912 in Richmond, Virginia. Specializing in gray and ductile iron sand castings, the company produces parts ranging from 1 lb. to 400 lbs. using phenolic urethane bonded sand molding. They serve general industrial needs for both short runs and serial production, continuously evolving with modern casting technologies.', '{"capacity_notes":"Capable of producing gray and ductile iron sand castings from 1 lb. to 400 lbs. The no-bake molding line is most efficient for short runs of 25, 50, or 100 castings weighing 50 to 250 lbs.","certifications":[],"industries_served":["Railroad","Industrial Equipment","Agricultural Equipment","Heavy Equipment","Audio Equipment","Historical Restoration"],"overview":"OK Foundry Company, Inc. is a family-owned and operated jobbing foundry established in 1912 in Richmond, Virginia. Specializing in gray and ductile iron sand castings, the company produces parts ranging from 1 lb. to 400 lbs. using phenolic urethane bonded sand molding. They serve general industrial needs for both short runs and serial production, continuously evolving with modern casting technologies.","unique_value":"OK Foundry utilizes phenolic urethane no-bake (PUNB) binders for cope and drag molding, which creates strong molds and cores, allowing for complex cored and large format castings. They have a long history of innovation, including early adoption of induction melting in 1976 and resin-bonded sand molding by 1979. They also leverage 3D printed sand molds for prototyping and complex designs, while maintaining traditional pattern-making capabilities for historical reproductions."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-02 14:01:12.004+00', 83, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
