INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('874164f8-0065-4c0a-8a44-439f80463e7d', 'discovered-289fa9c9', 'LGM 3D', 'https://lgm3d.com', 'Minturn, CO, United States', 'Minturn', 'United States', 39.5863749, -106.4308631, ARRAY['binder-jetting','sla','fdm'], ARRAY['nylon','plastic','gypsum'], NULL, NULL, NULL, true, false, 0, 0, 'LGM 3D specializes in creating highly detailed physical 3D models for architectural, industrial design, and sales professionals. With over 20 years of experience, they leverage 3D printing, laser cutting, and CNC machining to produce accurate and visually compelling models. Their expertise spans from concept models to complex interactive displays, serving a diverse clientele.', '{"capacity_notes":"LGM 3D operates in-house with monochrome and color binder jet 3D printers, SLA plastic 3D printers, a 3-axis CNC milling machine (48\" x 96\" platform), and laser cutting/etching capabilities (40\" x 28\" platform). They also have a wood shop and paint booths for advanced finishing.","certifications":[],"industries_served":["Architecture","Industrial Design","Construction","Real Estate Sales","Museums","Education","Land Planning","Urban Planning"],"overview":"LGM 3D specializes in creating highly detailed physical 3D models for architectural, industrial design, and sales professionals. With over 20 years of experience, they leverage 3D printing, laser cutting, and CNC machining to produce accurate and visually compelling models. Their expertise spans from concept models to complex interactive displays, serving a diverse clientele.","unique_value":"LGM 3D combines decades of 3D printing expertise with backgrounds in architecture, engineering, and industrial design, offering a unique understanding of client needs. They provide comprehensive services including CAD data optimization, file repair, and traditional craft skills alongside cutting-edge production methods like full-color binder jetting and SLA for fine details."}', '{}'::jsonb, NULL, 'Contact for estimate', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-08 18:00:45.039+00', 82, 0, '2026-02-02 11:34:03.513259+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
