INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('e6f3975e-4f15-447a-b591-a9ae088aa364', 'treatstock-rivet3d', 'Rivet3D LLC', 'https://www.rivet3d.com', 'Missoula, MT, United States', 'Missoula', 'United States', 44.5645659, -123.2620435, ARRAY['FDM','3D Printing','CNC Machining'], ARRAY['PLA','TPU','PETG'], NULL, NULL, NULL, false, false, 0, 0, 'Rivet3D LLC specializes in mechanical design and development, offering engineering consultation, analysis, and design services. The company helps inventors and businesses analyze models and complete their projects, focusing on delivering high-quality work and meeting agreed-upon milestones. They provide comprehensive support from initial concept to final product realization.', '{"capacity_notes":"Rivet3D primarily offers design and engineering services, including CAD, drawing generation, image rendering, and 3D printing as part of their development process. They do not appear to offer direct manufacturing services or have specific production capacity details listed.","certifications":[],"industries_served":[],"overview":"Rivet3D LLC specializes in mechanical design and development, offering engineering consultation, analysis, and design services. The company helps inventors and businesses analyze models and complete their projects, focusing on delivering high-quality work and meeting agreed-upon milestones. They provide comprehensive support from initial concept to final product realization.","unique_value":"Rivet3D offers a personalized partnership approach to mechanical design and development, emphasizing clear communication, detailed analysis (static stress, flow, thermal modeling), and support for patent filing. Their expertise lies in transforming client visions into reality through meticulous engineering and design."}', '{}'::jsonb, NULL, 'Varies by project', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-11 09:00:16.407+00', 70, 5, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
