INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('1b29eed1-ddc5-4f44-aa5c-3db30663c67f', 'treatstock-diamond-w', 'Diamond W Custom Machine Works', 'https://diamondwmachine.com', 'Agra, KS, United States', 'Agra', 'United States', 39.761678, -99.119254, '{}', ARRAY['steel','aluminum','stainless-steel'], NULL, NULL, NULL, true, false, 0, 0, 'Diamond W Custom Machine Works is a family-owned and operated business based in rural northwest Kansas, serving customers globally. Founded in 2015 by Eric Wagner, the company specializes in precision CNC machining, engineering design, 3D printing, welding, and fabrication. With nearly 20 years of engineering experience, they are dedicated to bringing concepts to life with innovation, precision, and efficiency.', '{"capacity_notes":"The company offers a complete range of services from 3D printing test pieces to machining final products. They handle various manufacturing jobs, including smaller tasks to streamline client production lines. They utilize Solidworks 3D modeling software for design and have in-house expertise for CNC plasma, waterjet, and laser cutting.","certifications":[],"industries_served":["Industrial Manufacturing","Engineering","Health Care","Veterinary Medicine","Food & Agriculture","Research & Development"],"overview":"Diamond W Custom Machine Works is a family-owned and operated business based in rural northwest Kansas, serving customers globally. Founded in 2015 by Eric Wagner, the company specializes in precision CNC machining, engineering design, 3D printing, welding, and fabrication. With nearly 20 years of engineering experience, they are dedicated to bringing concepts to life with innovation, precision, and efficiency.","unique_value":"Diamond W Custom Machine Works leverages nearly two decades of practical engineering experience to offer comprehensive services from design consulting and prototyping to manufacturing support and specialized cutting. They excel in reverse-engineering obsolete parts and providing MIG/TIG welding for steel, aluminum, and stainless steel, along with finishing services like powder coating and anodizing."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-06 03:00:44.907+00', 85, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
