INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('ac62d9e2-9d21-4ce2-8b0a-6d7840950d09', 'discovered-f7c20c08', 'Articon', 'https://articon.com', 'Irvine, CA, United States', 'Irvine', 'United States', 33.6856969, -117.825981, ARRAY['dlp'], ARRAY['titanium-grade-5','resin','zirconia','peek','cobalt-chrome'], NULL, NULL, NULL, true, false, 0, 0, 'Articon specializes in providing high-precision dental digital solutions, including milled titanium implant bars and a range of dental 3D printers, resins, and milling machines. Based in California, the company focuses on delivering products with exceptional fit, strength, and fast turnaround times for dental labs and clinicians. They offer a comprehensive suite of dental manufacturing technologies and materials.', '{"capacity_notes":"Offers a fast 24-hour turnaround for precision-milled titanium implant bars. Ships most orders same day via UPS within the US, with worldwide shipping available upon special request.","certifications":[],"industries_served":["Dental"],"overview":"Articon specializes in providing high-precision dental digital solutions, including milled titanium implant bars and a range of dental 3D printers, resins, and milling machines. Based in California, the company focuses on delivering products with exceptional fit, strength, and fast turnaround times for dental labs and clinicians. They offer a comprehensive suite of dental manufacturing technologies and materials.","unique_value":"Articon provides precision-milled dental and implant bars with passive fit and a fast 24-hour turnaround, utilizing Grade 5 titanium. They also supply a wide range of dental 3D printers (Asiga), resins, milling machines (Imes-Icore), and CAD/CAM software, positioning them as a comprehensive provider for digital dentistry workflows."}', '{}'::jsonb, NULL, '24-hour turnaround for milled bars', true, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 16:01:13.085+00', 92, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('7e439e4f-b956-4d6e-a3e9-d2a8be61fd73', 'stratasys-direct', 'Stratasys Direct – Industrial 3D Printing & Manufacturing Se', 'https://www.stratasys.com/en/stratasysdirect/', 'USA', NULL, 'United States', 44.865025, -93.463402, ARRAY['polyjet','sla','dlp','fdm','saf','sls','mjf'], ARRAY['resins','thermoplastics','polymers'], 'main-brand', 'free-listing', 'northamerica', true, false, 0, 0, 'Stratasys Direct is a leading 3D printing and advanced manufacturing service bureau with over 30 years of experience. They offer a wide range of industrial-grade additive manufacturing technologies and over 50 engineering-grade materials. Specializing in high-requirement projects, they serve industries such as aerospace, automotive, and medical.', NULL, '{"TechnologyID":["material-jetting","mjf","sla","sls","fdm","dlp","saf"],"affiliatelinkid":"https://www.stratasys.com/en/stratasysdirect/","cardStyle":"main-brand","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"7665 Commerce Way, Eden Prairie, MN 55344, USA","building":""},"metalid":[],"thermoplasticid":[],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-19 23:00:43.903+00', 0, 1, '2025-10-23 16:57:30.825202+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('c4132978-8115-4d80-8ce1-02162f331197', 'discovered-37d0f516', 'Boston Micro Fabrication (BMF)', 'https://bmf3d.com', 'Boston, MA, United States', 'Boston', 'United States', 42.3588336, -71.0578303, ARRAY['sla'], ARRAY['ceramic','resin','photosensitive-resin'], NULL, NULL, NULL, true, false, 0, 0, 'Boston Micro Fabrication (BMF) is a global leader in advanced additive manufacturing, specializing in Projection Micro Stereolithography (PµSL) technology. The company enables the 3D printing of true microstructures with ultra-high resolution (2µm~50µm) and precision. BMF''s solutions provide complete design freedom for intricate, exact, and replicable parts at a scale and tolerance comparable to micro injection molded parts.', '{"capacity_notes":"BMF''s microArch® series printers offer various build sizes, including 100 × 100 × 75mm, 100 x 100 x 50mm, and smaller, with layer thicknesses ranging from 5μm to 50μm. The systems are designed for industrial prototyping and short-run production, capable of producing parts with surface roughness as low as 0.4-0.8µm Ra (top).","certifications":[],"industries_served":["Medical Devices","Electronics","Microfluidics","Aerospace","Defense","Marine"],"overview":"Boston Micro Fabrication (BMF) is a global leader in advanced additive manufacturing, specializing in Projection Micro Stereolithography (PµSL) technology. The company enables the 3D printing of true microstructures with ultra-high resolution (2µm~50µm) and precision. BMF''s solutions provide complete design freedom for intricate, exact, and replicable parts at a scale and tolerance comparable to micro injection molded parts.","unique_value":"BMF''s core strength lies in its proprietary Projection Micro Stereolithography (PµSL) technology, which allows for ultra-high resolution (down to 2µm) and precision in 3D printing, matching the tolerances of micro injection molding. They also offer dual-resolution functionality, capable of printing at 10µm or 25µm, or switching within the same build, and hold a U.S. patent for this technology."}', '{}'::jsonb, NULL, 'Not specified', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-09 08:00:58.965+00', 85, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('bd7d00bd-46f7-48c0-a5df-0e0313549c70', 'treatstock-originate-3d', 'Originate 3D', 'https://originate3d.com', NULL, 'Dallas', 'United States', 32.7762719, -96.7968559, ARRAY['dlp','sla','fdm'], ARRAY['PLA','ABS','Nylon'], NULL, NULL, NULL, true, false, 0, 0, 'Originate 3D is a product development and small-scale manufacturing company offering reliable and flexible 3D printing services. With a combined fifty years of experience, they specialize in designing and bringing concepts to market, from one-off prints to hundreds per week. They provide full-service solutions including product development, engineering design, and manufacturing.', '{"capacity_notes":"Capable of producing from one-off prints to hundreds per week. The company mentions having an \"Elegoo Jupiter\" which is a large MSLA printer, indicating a focus on resin-based production.","certifications":[],"industries_served":[],"overview":"Originate 3D is a product development and small-scale manufacturing company offering reliable and flexible 3D printing services. With a combined fifty years of experience, they specialize in designing and bringing concepts to market, from one-off prints to hundreds per week. They provide full-service solutions including product development, engineering design, and manufacturing.","unique_value":"Originate 3D distinguishes itself with a combined fifty years of experience in product development and manufacturing, offering comprehensive services from initial design and 3D modeling to small-scale production. They can assist with both new ideas and reverse engineering out-of-production parts."}', '{}'::jsonb, NULL, NULL, false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-07 18:00:30.153+00', 73, 0, '2026-02-03 09:03:19.200102+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0cbb7d18-1625-410d-9f09-ae3a2fa7a0de', 'discovered-133d74fd', 'American Additive Manufacturing', 'https://americanadditive.com', 'United States', NULL, 'United States', 40.1842455, -75.1390524, ARRAY['fdm','sla','sls','mjf','dmls','slm'], ARRAY['ultem-9085','ultem-1010','peek','pekk'], NULL, NULL, NULL, true, false, 0, 0, 'American Additive Manufacturing provides advanced additive manufacturing services, specializing in rapid prototyping, large-scale production, and custom part manufacturing. They leverage cutting-edge FDM, SLA, SLS, MJF, DMLS, and SLM technologies to deliver precision-engineered solutions. The company is committed to supporting the ''Made in USA'' initiative and improving supply chains for various industries.', '{"capacity_notes":"Offers large build envelopes up to 36” x 24” x 36” for industrial applications. Utilizes multiple machines across various technologies including Stratasys Fortus 900, 450, 370, Formlabs Fuse 1+ 30W, Formlabs 3B, 3L, HP MJF 4200 and 5200, EOS M270, M280, and SLM 280.","certifications":["ISO 9001:2015","AS9100D","ITAR","CMMC II","AIS (Aircraft Interiors Solution) certified"],"industries_served":["Aerospace & Defense","Industrial","Automation","Robotics","Automotive","Architectural"],"overview":"American Additive Manufacturing provides advanced additive manufacturing services, specializing in rapid prototyping, large-scale production, and custom part manufacturing. They leverage cutting-edge FDM, SLA, SLS, MJF, DMLS, and SLM technologies to deliver precision-engineered solutions. The company is committed to supporting the ''Made in USA'' initiative and improving supply chains for various industries.","unique_value":"American Additive Manufacturing offers a comprehensive suite of additive manufacturing technologies including FDM (with Stratasys Fortus 900 AIS/AICS, 450, 370), SLS (Formlabs Fuse 1+ 30W), SLA (Formlabs 3B, 3L), HP MJF (4200 and 5200), DMLS (EOS M270 and M280), and SLM (280). They specialize in tackling obsolescence and supply chain challenges for legacy assets through their MRO expertise and dedicated Design & Engineering team."}', '{}'::jsonb, NULL, 'Not specified', false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-10 07:00:37.28+00', 95, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('308ec091-a7b2-4b94-8009-613ed5755820', 'discovered-4304566d', 'General Foundry', 'https://genfoundry.com', 'San Leandro, CA, United States', 'San Leandro', 'United States', 37.7249296, -122.1560768, ARRAY['binder-jetting'], ARRAY['aluminum','zinc'], NULL, NULL, NULL, true, false, 0, 0, 'General Foundry Service, with over 70 years of history, specializes in turnkey aluminum and zinc-aluminum casting solutions. They provide custom cast parts with smooth surface finishes and tight tolerances for prototype, low, and intermediate volume production. The company offers a range of casting processes, including 3D printed sand mold casting, along with secondary CNC machining and finishing services.', '{"capacity_notes":"Specializes in prototype, low, and intermediate volume production for aluminum and zinc-aluminum castings, utilizing five complementary casting processes.","certifications":["ISO 9001","ITAR Registered"],"industries_served":["Medical / Surgical Equipment","Biotech / Life Sciences","Robotics & Electromechanical Systems","Homeland Security / Military / Defense","Semi-Conductor Equipment","Telecom / Networking","GPS Equipment"],"overview":"General Foundry Service, with over 70 years of history, specializes in turnkey aluminum and zinc-aluminum casting solutions. They provide custom cast parts with smooth surface finishes and tight tolerances for prototype, low, and intermediate volume production. The company offers a range of casting processes, including 3D printed sand mold casting, along with secondary CNC machining and finishing services.","unique_value":"General Foundry offers a comprehensive turnkey solution for aluminum and zinc-aluminum castings, integrating multiple casting processes including 3D printed sand molds, secondary CNC machining, and surface finishing. Their long history and customer-centric approach ensure repeatable tolerances and dependable service for diverse production needs."}', '{}'::jsonb, NULL, 'Not specified', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 19:01:19.68+00', 93, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('03a9c6f7-eb87-4f85-b915-2daa0df2bf3a', 'discovered-48d0b349', 'Precipart', 'https://precipart.com', 'Farmingdale, NY, United States', 'Farmingdale', 'United States', 40.7328811, -73.4458564, ARRAY['Micro 3D Printing','Micro Laser Sintering'], ARRAY['Sintered Metals','Ceramics'], NULL, NULL, NULL, false, false, 0, 0, 'Precipart is a global engineering and manufacturing company specializing in high-precision custom solutions for the Medical, Aerospace, and Industrial markets since 1950. They offer expertise in engineering, design, and manufacturing of precision gears, mechanical components, assemblies, and motion control solutions. With offices in Switzerland, the U.S., the U.K., and Ireland, Precipart partners with clients throughout the entire manufacturing process.', '{"capacity_notes":"Precipart focuses on high volume, large scale production of precision components, gears, assemblies, and full instruments.","certifications":[],"industries_served":["Medical","Aerospace","Industrial","Space Systems","Medtech"],"overview":"Precipart is a global engineering and manufacturing company specializing in high-precision custom solutions for the Medical, Aerospace, and Industrial markets since 1950. They offer expertise in engineering, design, and manufacturing of precision gears, mechanical components, assemblies, and motion control solutions. With offices in Switzerland, the U.S., the U.K., and Ireland, Precipart partners with clients throughout the entire manufacturing process.","unique_value":"Precipart has a long history of innovation, contributing to diverse projects from early gramophones to robotic surgery and space exploration. They emphasize a unique combination of engineering, design, and manufacturing expertise, focusing on micro-details and high-volume production for complex custom mechanical and motion control solutions."}', '{}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-10 14:01:08.823+00', 67, 5, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('ee144c66-91c5-4279-9829-eddcdd145339', 'discovered-e5342c2f', 'Perfect 3D', 'https://perfect3d.com', 'Dayton, OH, United States', 'Dayton', 'United States', 39.8208998, -84.0193858, '{}', ARRAY['ceramic','alumina','silica','zircon'], NULL, NULL, NULL, true, false, 0, 0, 'PERFECT-3D, a division of Renaissance Services Inc., specializes in ceramic additive manufacturing for investment casting tooling. The company focuses on producing ceramic cores, molds, and filters for aerospace and defense applications. Their approach leverages cutting-edge AM to create high-quality tooling, significantly reducing costs and lead times compared to conventional methods.', '{"capacity_notes":"PERFECT-3D operates from a 6,000 sq ft climate-controlled facility, housing all capabilities for ceramic tooling production including material mixing, 3D printing, parts cleaning, and high-temperature firing. They can produce ceramic components ranging in size from 1” to 20” with intricate features as small as 0.020”.","certifications":[],"industries_served":["Aerospace","Defense","Investment Casting"],"overview":"PERFECT-3D, a division of Renaissance Services Inc., specializes in ceramic additive manufacturing for investment casting tooling. The company focuses on producing ceramic cores, molds, and filters for aerospace and defense applications. Their approach leverages cutting-edge AM to create high-quality tooling, significantly reducing costs and lead times compared to conventional methods.","unique_value":"PERFECT-3D has developed proprietary and patent-pending techniques for directly 3D printing ceramic molds for high-temperature nickel-based alloys, steel, and aluminum castings, allowing foundries to bypass traditional tooling steps. They also have patented techniques for ceramic 3D printing of high-quality filters with tightly controlled flow rates."}', '{}'::jsonb, NULL, '1 week for cores, 30 days for molds', false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 11:00:52.819+00', 82, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('a4360dbd-a028-46df-b30b-02bd433e9696', 'discovered-59dd71bd', 'Calix Ceramic Solutions', 'https://calixceramics.com', 'Buffalo, NY, United States', 'Buffalo', 'United States', 42.8864163, -78.8781493, ARRAY['ceramic'], ARRAY['ceramic','silicon-carbide'], NULL, NULL, NULL, true, false, 0, 0, 'Calix Ceramic Solutions specializes in providing high-performance, advanced ceramic materials and products, focusing on precision and durability. They offer tailored solutions across technical ceramics, fine ceramics, and ceramic composites. The company''s advanced ceramic manufacturing addresses challenges in industries such as fluid handling, chemical processing, energy, and industrial machinery, including 3D printed ceramic solutions.', '{"capacity_notes":"Calix Ceramic Solutions commits lab time and development resources to find solutions for unique customer problems. They leverage a network of academic partners and commercial organizations to provide the necessary materials and technology for various applications.","certifications":[],"industries_served":["Fluid Handling","Chemical Processing","Energy","Industrial Machinery"],"overview":"Calix Ceramic Solutions specializes in providing high-performance, advanced ceramic materials and products, focusing on precision and durability. They offer tailored solutions across technical ceramics, fine ceramics, and ceramic composites. The company''s advanced ceramic manufacturing addresses challenges in industries such as fluid handling, chemical processing, energy, and industrial machinery, including 3D printed ceramic solutions.","unique_value":"Calix Ceramic Solutions offers a complete portfolio of technical ceramics, specializing in fine ceramics composed of oxides, non-oxides, and composites. They provide extensive ceramic engineering services, including material characterization, failure analysis, microstructural analysis, and custom material development. Their expertise extends to ceramic bonding, thermal ceramics services, and ceramic-to-metal integration."}', '{}'::jsonb, NULL, NULL, false, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-09 06:01:36.7+00', 82, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('612a0898-d438-4f88-bd78-39be438bef60', 'discovered-b42879b7', 'Airwolf 3D', 'https://airwolf3d.com', 'Miami, FL, United States', 'Miami', 'United States', 25.7741566, -80.1935973, ARRAY['fdm'], ARRAY['abs','polycarbonate','carbon-fiber-abs','tpu','petg','nylon','pla','hips','pp','nylon-910','nylon-cofa'], NULL, NULL, NULL, true, false, 0, 0, 'Airwolf 3D, founded in 2012, specializes in designing and manufacturing professional-grade FDM 3D printers and providing 3D printing services. They are known for their large-format printers capable of producing huge, engineering-grade parts from materials like ABS and polycarbonate. The company is committed to U.S.-based manufacturing, ensuring high accuracy, quick print speeds, and a seamless 3D printing experience.', '{"capacity_notes":"Offers 3D printing services with a maximum standard build volume of 22″ x 12″ x 22″, with larger sizes available upon request. Minimum part price is $100, and minimum order is $300, catering to bulk orders and industrial-grade FDM printing.","certifications":["Made in USA"],"industries_served":["Education","Automotive","Architecture","Manufacturing","Medical"],"overview":"Airwolf 3D, founded in 2012, specializes in designing and manufacturing professional-grade FDM 3D printers and providing 3D printing services. They are known for their large-format printers capable of producing huge, engineering-grade parts from materials like ABS and polycarbonate. The company is committed to U.S.-based manufacturing, ensuring high accuracy, quick print speeds, and a seamless 3D printing experience.","unique_value":"Airwolf 3D distinguishes itself by manufacturing its own industrial-grade FDM 3D printers and precision-engineered filaments in the USA, offering large build volumes (up to 24” x 12” x 22” for printers, 22” x 12” x 22” for service) and specialized expertise in printing high-temperature, engineering-grade ABS and polycarbonate parts with minimal warping. They also offer proprietary Wolfbite adhesion solutions and HydroFill water-soluble support material."}', '{}'::jsonb, NULL, '1-3 business days', true, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 23:00:53.632+00', 98, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('f650dd36-7ab2-4621-a9e0-8675d660c00b', 'partzpro', 'PartZpro – Hassle-Free Parts Sourcing & On-Demand Manufactur', 'https://www.partzpro.com', 'Irvine, CA, United States', 'Irvine', 'United States', 33.64492, -117.744068, ARRAY['cnc-machining'], ARRAY['aluminum','aluminum-6082'], NULL, 'free-listing', 'northamerica', true, false, 0, 0, 'partZpro is a fintech-driven manufacturing platform that offers hassle-free parts sourcing and on-demand manufacturing. It eliminates traditional supply chain latency by providing direct factory-to-door shipping and transparent pricing. The platform leverages AI for cost-driver analysis and offers US payment protection, ensuring quality and accountability for custom parts.', '{"capacity_notes":"The platform offers access to a massive network capacity of 100,000+ parts. It facilitates production runs from 1 to 10,000+ parts and connects users with premier precision manufacturing shops utilizing advanced 5-Axis CNC Machines.","certifications":["ISO-2768"],"industries_served":[],"overview":"partZpro is a fintech-driven manufacturing platform that offers hassle-free parts sourcing and on-demand manufacturing. It eliminates traditional supply chain latency by providing direct factory-to-door shipping and transparent pricing. The platform leverages AI for cost-driver analysis and offers US payment protection, ensuring quality and accountability for custom parts.","unique_value":"partZpro distinguishes itself with a ''Fintech of Manufacturing'' approach, offering US Payment Protection where funds are held until parts are verified by the customer. It provides an ''open-book'' model with original factory invoices, AI-driven cost-driver analysis, and direct factory-to-door shipping to eliminate middlemen and reduce lead times. The platform also features a ''US Shield'' for legal and financial security in international sourcing."}', '{"TechnologyID":["dmp","fdm","material-jetting","mjf","sla","sls","slm"],"affiliatelinkid":"https://www.partzpro.com","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"8583 Irvine Center Dr #180, Irvine, CA 92618, USA","building":""},"metalid":["aluminum-aisi10mg","titanium-ti-6al-4v","steel","stainless-steel-316l","maraging-steel","inconel-625","ni625"],"photopolymerid":["formlabs-flexible-resin-80a","formlabs-durable-resin"],"thermoplasticid":["photopolymer-rigid","petg","pei-ultem-9085-stratasys","pei-ultem-1010-stratasys","pc-or-pc-abs","pc","pa11-sls","pa-gf","pa-af","tpu-70-a-white","tpu-mjf","pa-12-bluesint","nylon-12-glass-bead-filled-gf","nylon-12-flame-retardant-fr","nylon-12-aluminum-filled-af","pa-12","nylon-12","formlabs-clear-resin","accura-25","absplus-stratasys","abs-m30i","abs-like-black"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, '7-10 days', true, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:06:04.746+00', 78, 0, '2025-10-23 16:57:32.404872+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('60a52d7a-6f93-4cff-93d8-bc9770805682', 'discovered-e9bb9279', 'Empire Group', 'https://empiregroupusa.com', 'Attleboro, MA, United States', 'Attleboro', 'United States', 41.9439695, -71.2804301, ARRAY['mjf','sla','dlp','fdm'], ARRAY['HTL Resin','RG Resin'], NULL, NULL, NULL, true, false, 0, 0, 'Empire Group has been delivering high-quality, low-volume manufacturing solutions for over 20 years. They offer in-house capabilities ranging from high-fidelity prototyping to production, utilizing a broad array of advanced technologies. The company focuses on providing design and engineering support alongside high-tech manufacturing services to meet diverse project needs.', '{"capacity_notes":"The company emphasizes in-house capabilities for both prototyping and low-volume production. They have a painting department offering low-volume production painting and custom color formulation.","certifications":["ISO 9001","ISO 27001","ITAR"],"industries_served":["Aerospace/Aviation","Automotive","Consumer Products","Contract Manufacturing","Electronics","Engineering/Design/Prototyping","Equipment - Commercial","Equipment - Electronic","Equipment - Industrial","Government/Defense","Medical Devices"],"overview":"Empire Group has been delivering high-quality, low-volume manufacturing solutions for over 20 years. They offer in-house capabilities ranging from high-fidelity prototyping to production, utilizing a broad array of advanced technologies. The company focuses on providing design and engineering support alongside high-tech manufacturing services to meet diverse project needs.","unique_value":"Empire Group offers a powerful combination of advanced technologies and direct access to a team of experts, specializing in high-fidelity prototyping and low-volume manufacturing. They provide comprehensive services from design and engineering support to various advanced manufacturing capabilities, including specialized finishing options like Cerakoting."}', '{}'::jsonb, NULL, NULL, true, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 12:00:38.11+00', 85, 0, '2026-02-02 12:22:49.614381+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('30e2393f-18b1-475e-85b4-62123afad557', 'fictiv', 'Fictiv – Digital Manufacturing Platform & Custom Parts', 'https://www.fictiv.com/production', 'Oakland, CA, USA', 'Oakland', 'United States', 37.805306, -122.27058, ARRAY['fdm','sls','sla','polyjet','mjf'], ARRAY['Nylon 12','Nylon 12 Mineral Filled','Nylon PA-12','PA Aluminum Filled','PA Glass Filled','PA-11 (SLS)','PA-12','PA-12 BlueSint','PA-12 Carbon Filled','PC/PC-ABS','PEI ULTEM 1010','PEI ULTEM 9085','PETG','Polycarbonate','Polypropylene (MJF)','TPU MJF'], NULL, 'free-listing', 'northamerica', true, false, 0, 0, 'Fictiv is a digital manufacturing platform that streamlines the entire product manufacturing lifecycle, offering scalable solutions for prototyping and production. They combine expert engineering, quality assurance, supplier management, and logistics to deliver custom parts. Fictiv serves as a global supply chain partner, leveraging manufacturing centers in India, Mexico, China, and the U.S. to optimize logistics and mitigate risk.', '{"capacity_notes":"Fictiv offers precision CNC machining for parts up to 34 feet. They provide no minimum order quantity and support high-volume injection molding. Their global manufacturing centers in India, Mexico, China, and the U.S. enable scalable production.","certifications":["ISO 9001:2015","AS9100D","ISO 13485:2016","IATF 16949:2016","NADCAP","NABL"],"industries_served":["Aerospace","Consumer Products","Automotive","Medical","Climate Tech","Robotics","Semiconductor","eVTOL"],"overview":"Fictiv is a digital manufacturing platform that streamlines the entire product manufacturing lifecycle, offering scalable solutions for prototyping and production. They combine expert engineering, quality assurance, supplier management, and logistics to deliver custom parts. Fictiv serves as a global supply chain partner, leveraging manufacturing centers in India, Mexico, China, and the U.S. to optimize logistics and mitigate risk.","unique_value":"Fictiv differentiates itself through its digital supply chain platform, which provides instant quotes, expert DFM, and automated production updates. They offer a global network of highly vetted manufacturing partners across four regions (India, Mexico, China, U.S.) for enhanced supply chain resilience and optimized logistics."}', '{"TechnologyID":["dlp","dmls","fdm","material-jetting","mjf","sla","sls"],"affiliatelinkid":"https://www.fictiv.com/production","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"1611 Telegraph Ave, Oakland, CA 94612, USA","building":""},"metalid":[],"thermoplasticid":["tpu-mjf","petg","pei-ultem-9085-stratasys","pei-ultem-1010-stratasys","pc-or-pc-abs","pc","pa11-sls","pa-gf","pa-af","pa-12-carbon-filled","pa-12-bluesint","pa-12","polypropylene-mjf","nylon-pa-12","nylon-12-mineral-filled-hst","nylon-12"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, '2 days (CNC)', true, true, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-02-05 13:02:43.139+00', 70, 1, '2025-10-23 16:57:36.567538+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('faa9b4f2-6c7b-466e-99ef-2d5dde1b44a7', '3deo', '3DEO', 'https://www.3deo.co/', 'Torrance, CA, USA', 'Torrance', 'United States', 33.806406, -118.337672, ARRAY['metal-3d-printing','intelligent-layering®-(proprietary-metal-am)'], ARRAY['metal'], 'white', 'free-listing', 'northamerica', true, false, 0, 0, '3DEO specializes in high-volume metal 3D printing of small, complex parts using its proprietary Intelligent Layering® technology. They offer design for additive manufacturing services, serving industries like medical, aerospace, industrial, consumer products, automotive, and semiconductor.', NULL, '{"TechnologyID":["binder-jetting"],"affiliatelinkid":"https://www.3deo.co/","cardStyle":"white","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"24225 Garnier St, Torrance, CA 90505, USA","building":""},"metalid":["steel","stainless-steel-316l","stainless-steel-17-4ph"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-01-19 14:00:33.58+00', 0, 1, '2025-10-23 16:57:28.294467+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('71923557-39a1-448a-9ffe-38d74ae285b7', '100kgarages', '100kGarages', 'https://100kgarages.com/', NULL, NULL, NULL, NULL, NULL, ARRAY['fdm'], ARRAY['wood','metal'], NULL, NULL, NULL, true, false, 0, 0, '100kGarages is an online platform connecting individuals with designs or ideas to digital fabricators, referred to as "Fabbers." The service facilitates the creation of custom items using 2D and 3D digital fabrication tools, including 3D printers. It aims to foster collaboration within the maker community, offering a free matchmaking service to find local Fabbers.', '{"capacity_notes":"The platform connects users to a distributed network of Fabbers, each with their own capacity. It does not specify a centralized production capacity.","certifications":[],"industries_served":[],"overview":"100kGarages is an online platform connecting individuals with designs or ideas to digital fabricators, referred to as \"Fabbers.\" The service facilitates the creation of custom items using 2D and 3D digital fabrication tools, including 3D printers. It aims to foster collaboration within the maker community, offering a free matchmaking service to find local Fabbers.","unique_value":"100kGarages acts as a free matchmaking service, connecting individuals directly with a network of local digital fabricators (Fabbers) who utilize various tools like CNC routers, laser cutters, and 3D printers. This platform specifically caters to custom product creation and also supports designers offering CAD services."}', '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-02-10 19:00:26.286+00', 63, 0, '2025-11-11 14:58:48.660984+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
