INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('49e6746a-f56c-4060-b26a-5611b36101db', 'gkn-additive', 'GKN Additive', 'https://www.gknpm.com/en/technologies/metal-additive-manufacturing/', 'Germany', NULL, 'Germany', 51.4359239, 6.9100197, ARRAY['slm','binder-jetting'], ARRAY['stainless-steel-316l','stainless-steel-17-4ph','aluminum-alsi10mg','titanium-ti-6al-4v','inconel-625','inconel-718','copper','tool-steel'], 'white', 'free-listing', 'europe', true, false, 0, 0, 'GKN Additive specializes in end-to-end metal additive manufacturing, offering metal AM powders, laser powder bed fusion, and binder jetting for industrial-grade parts. They provide comprehensive services from powder development to production-ready components, serving diverse industries with high-quality, reliable, and scalable solutions. The company focuses on advanced metal technologies, including rapid prototyping and high-volume production, with a strong commitment to sustainability.', NULL, '{"TechnologyID":["binder-jetting","dmls"],"affiliatelinkid":"https://www.gknpm.com/en/technologies/metal-additive-manufacturing/","cardStyle":"white","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"53 Bonn, Germany","building":""},"metalid":["inconel-625","ni625","maraging-steel","aluminum-aisi10mg","titanium-ti-6al-4v","steel","stainless-steel-316l","inconel-718"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', '85bdd257-45a1-4369-bbf1-f01569078bcd', '2026-01-30 14:48:25.214+00', 87, 1, '2025-10-23 16:57:26.228479+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('0421055c-c2da-4820-a9f8-63afc5f722e7', 'nanoo', 'NANOO', 'https://www.nanoo.cc', NULL, NULL, NULL, 13.4, 52.52, ARRAY['fdm','waam'], ARRAY['thermoplastic-composite'], NULL, NULL, NULL, true, false, 0, 0, 'Nanoo specializes in large format additive manufacturing (LFAM) using robotic systems to produce custom construction elements and large-scale parts. The company focuses on hybrid manufacturing, combining 3D printing with CNC machining for precision finishing. They aim to provide cost-effective and sustainable solutions for low-volume production of non-standard components.', '{"capacity_notes":"The company describes itself as a \"small and highly automated factory\" utilizing robots for large-scale part production.","certifications":[],"industries_served":["Construction","Aerospace & Defense","Energy","Marine","Automotive & Transportation","Furniture & Design"],"overview":"Nanoo specializes in large format additive manufacturing (LFAM) using robotic systems to produce custom construction elements and large-scale parts. The company focuses on hybrid manufacturing, combining 3D printing with CNC machining for precision finishing. They aim to provide cost-effective and sustainable solutions for low-volume production of non-standard components.","unique_value":"Nanoo utilizes a hybrid manufacturing technology that combines large format additive manufacturing (LFAM) with CNC machining, enabling the production of large, complex thermoplastic composite parts with precision finishing. Their robotic systems are designed for on-demand manufacturing of non-standard and custom construction elements."}', '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-02-11 03:00:29.45+00', 75, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('bc544800-0fc5-43ad-aa0a-861f7a794ce7', 'toray-metal-3d-printing-service', 'Toray (Metal 3D Printing Service)', 'https://www.tpc.toray', 'Japan', NULL, 'Japan', NULL, NULL, ARRAY['lpbf'], ARRAY['metal','thermoplastic-resin','thermosetting-resin'], NULL, NULL, NULL, true, false, 0, 0, 'Toray Precision is a pioneer in ultra-precision microfabrication technology, with a history dating back to 1955. The company specializes in manufacturing key components for synthetic fiber production and has expanded its expertise to various industrial fields. They offer advanced microfabrication services, including metal 3D printing, and provide solutions for complex manufacturing challenges.', '{"capacity_notes":"For thermal imprint processing, they can handle forming sizes up to 300x300 mm. Production capacity for other services is not specified, but they mention handling small-lot production for precision micro-parts.","certifications":[],"industries_served":["Textile","Electronics","Medical","Semiconductor","Aerospace","Scientific & Optical Instruments","Energy","Non-clinical Testing"],"overview":"Toray Precision is a pioneer in ultra-precision microfabrication technology, with a history dating back to 1955. The company specializes in manufacturing key components for synthetic fiber production and has expanded its expertise to various industrial fields. They offer advanced microfabrication services, including metal 3D printing, and provide solutions for complex manufacturing challenges.","unique_value":"Toray Precision leverages decades of experience in precision microfabrication, originally developed for synthetic fiber manufacturing, to offer specialized services like metal 3D printing and thermal imprint processing. Their unique capabilities include high-aspect-ratio micro-hole processing, advanced discharge machining for difficult-to-cut materials, and high-speed laser microfabrication, enabling them to produce highly precise and intricate components."}', '{}'::jsonb, NULL, 'Adjustable upon request for thermal imprint processing', false, false, '{}', 'a8cdfbed-db91-414a-b190-3ab1dbd6c7ae', '2026-02-10 22:00:49.787+00', 88, 0, '2025-11-11 15:21:59.136625+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('e3ecfc87-e34a-427f-ab8c-b53e1e54e9fa', 'discovered-481f3f70', 'TriMech Advanced Manufacturing Services', 'https://mfg.trimech.com', 'North America', NULL, 'North America', NULL, NULL, ARRAY['dmls','fdm','mjf','polyjet','saf','sla','sls'], ARRAY['nylon','nylon-pa-12','polymers','composites','metals','silicone','urethane','carbon-fiber'], NULL, NULL, NULL, true, false, 0, 0, 'TriMech Advanced Manufacturing Services has been helping companies improve productivity and profitability for over two decades. They offer end-to-end expertise in additive manufacturing, from rapid prototyping to full-scale production. Utilizing a range of industry-leading 3D printers and scanners, TriMech provides comprehensive solutions including design, manufacturing, and finishing services.', '{"capacity_notes":"TriMech maintains a robust lineup of additive and subtractive manufacturing equipment, including over 70 industrial 3D printers. They have shipped over 1 million parts and offer fully American and Canadian manufacturing options.","certifications":["ITAR"],"industries_served":["Aerospace","Architectural","Automotive","Consumer Product","Defense","High Tech","Industrial Equipment","Marine and Offshore","Medical","Mold, Tool and Die"],"overview":"TriMech Advanced Manufacturing Services has been helping companies improve productivity and profitability for over two decades. They offer end-to-end expertise in additive manufacturing, from rapid prototyping to full-scale production. Utilizing a range of industry-leading 3D printers and scanners, TriMech provides comprehensive solutions including design, manufacturing, and finishing services.","unique_value":"TriMech differentiates itself by offering a full suite of advanced manufacturing solutions, including traditional methods like Cast Urethane and CNC machining alongside 3D printing. They emphasize a ''human element'' approach, acting as advisors and partners, and possess deep expertise with over 70 in-house printers, providing real-world application knowledge. They also offer specialized finishing options like EMI shielding and electroplating, and are ITAR-compliant."}', '{}'::jsonb, NULL, '1-3 business days (3D Printing)', true, false, '{}', NULL, '2026-02-11 10:00:27.809+00', 92, 0, '2025-12-26 19:45:18.500573+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('eb33dc7e-b9bd-4c45-aa12-ae8892f7cbae', 'discovered-1da9b061', 'Norck', 'https://norck.com', 'United States, Germany, and Europe', NULL, 'United States, Germany, and Europe', NULL, NULL, ARRAY['fdm','sla','sls','mjf','dlp','material-jetting','binder-jetting','dmls','slm','ebm','lpbf'], ARRAY['plastic','metal'], NULL, NULL, NULL, false, false, 0, 0, 'Norck provides custom manufacturing and engineering solutions, offering a wide range of services including CNC machining, 3D printing, sheet metal fabrication, and injection molding. They serve various industries such as aerospace, automotive, and electronics, focusing on delivering precision components and robust supply chain solutions. Norck leverages AI to augment its engineering services, aiming for efficient and effective manufacturing processes.', '{"capacity_notes":"Norck has its own production capacity and access to hundreds of top-quality CNC machining, sheet metal, 3D printing, injection molding, and urethane casting providers across the United States, Germany, and Europe.","certifications":["ISO 9001:2015"],"industries_served":["Defense","Aerospace","Robotics","Energy","Electronics","Automotive","Industrial Equipment","Consumer Products"],"overview":"Norck provides custom manufacturing and engineering solutions, offering a wide range of services including CNC machining, 3D printing, sheet metal fabrication, and injection molding. They serve various industries such as aerospace, automotive, and electronics, focusing on delivering precision components and robust supply chain solutions. Norck leverages AI to augment its engineering services, aiming for efficient and effective manufacturing processes.","unique_value":"Norck distinguishes itself by offering access to a vast production capacity through its own facilities and a network of hundreds of top-quality manufacturing providers across the United States, Germany, and Europe. They utilize artificial intelligence to augment engineering services, developing tools like RapidCAD for enhanced efficiency and design for manufacturability, and prioritize carbon-neutral compliant suppliers."}', '{}'::jsonb, NULL, NULL, false, true, '{}', NULL, '2026-02-10 17:00:46.098+00', 53, 1, '2025-12-26 19:36:27.281816+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('b60a9d84-7eab-4616-ae8d-6cff513e041c', 'nugae', 'NUGAE', 'https://nugae.tech', NULL, NULL, NULL, 13.4, 52.52, ARRAY['fdm'], ARRAY['composite','thermoplastic','glass-fiber','carbon-fiber'], NULL, NULL, NULL, true, false, 0, 0, 'NUGAE specializes in large-format robotic 3D printing, leveraging over 10 years of R&D to produce ultra-light, strong, and recyclable composite thermoplastic components. Their technology enables the creation of structural elements up to 3m x 1.5m x 1m, offering significant weight reduction and enhanced resistance to marine agents. NUGAE focuses on delivering innovative solutions for various applications, including core elements for sandwich structures, ready-to-use prototypes, and molds.', '{"capacity_notes":"Capable of printing large-format parts up to 3m x 1.5m x 1m. The technology allows for 5x faster production and uses 20x less material compared to traditional methods.","certifications":[],"industries_served":[],"overview":"NUGAE specializes in large-format robotic 3D printing, leveraging over 10 years of R&D to produce ultra-light, strong, and recyclable composite thermoplastic components. Their technology enables the creation of structural elements up to 3m x 1.5m x 1m, offering significant weight reduction and enhanced resistance to marine agents. NUGAE focuses on delivering innovative solutions for various applications, including core elements for sandwich structures, ready-to-use prototypes, and molds.","unique_value":"NUGAE''s unique value lies in its proprietary large-format robotic 3D printing technology, developed over a decade of R&D. This system can print composite thermoplastic elements up to 3m x 1.5m x 1m, offering 80% lighter pieces, 20% increased resistance to marine agents, and 5x faster production compared to standard techniques. They offer three distinct product types: Nu-Core for sandwich structures, Nu-Shape for prototypes, and Nu-Mold for tooling."}', '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-02-10 18:00:49.169+00', 82, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('46d35e40-8044-42fb-bd12-6bec39e1e42d', 'jiga', 'Jiga', 'https://jiga.io', NULL, NULL, NULL, NULL, NULL, ARRAY['fdm','sls','sla','mjf','polyjet','dmls','dlp'], ARRAY['abs','acrylic','delrin','nylon-6','nylon-66','pe','peek','pei','pes','pet','pfa','pmma','polycarbonate','polypropylene','pom','pp','pps','ppsu','ptfe','pvc','stainless-steel','stainless-steel-301','stainless-steel-304','stainless-steel-316','stainless-steel-316l','stainless-steel-904l','tool-steel','hastelloy-x','titanium-ti-6al-4v','titanium','tungsten','zinc','aluminum','bronze','steel','copper','brass','gold-plated-brass','ceramic'], NULL, NULL, NULL, true, false, 0, 0, 'Jiga is a manufacturing platform that connects buyers directly with a global network of vetted manufacturers for custom parts. They streamline the sourcing process from request to delivery, offering competitive human quotes and transparent communication. Jiga focuses on speeding up workflows and ensuring quality for both prototyping and mass production needs.', '{"capacity_notes":"Jiga connects users to a global network of vetted machine shops capable of handling projects from R&D to mass production. CNC machining capabilities range from simple drill press machines to advanced 5-axis and 6-axis machining centers, with part sizes from 0.7\"x0.7\"x0.7\" to 630\"x115\"x49\".","certifications":["ISO 9001:2015","ISO/IEC 90003","AS9100D","ISO 13485:2016","ITAR","EAR"],"industries_served":[],"overview":"Jiga is a manufacturing platform that connects buyers directly with a global network of vetted manufacturers for custom parts. They streamline the sourcing process from request to delivery, offering competitive human quotes and transparent communication. Jiga focuses on speeding up workflows and ensuring quality for both prototyping and mass production needs.","unique_value":"Jiga''s unique value lies in its direct-to-manufacturer communication model, which fosters transparent collaboration and allows for DFM feedback. The platform guarantees quality and on-time delivery, offering a streamlined RFQ process and significant cost and lead time reductions for custom parts."}', '{}'::jsonb, NULL, '5 days', true, true, '{}', NULL, '2026-02-10 21:00:43.842+00', 85, 0, '2025-11-11 14:58:48.660984+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('af59f131-45d7-4fb7-bca0-956836ff4ccd', 'rev3rd', 'REV3RD', 'https://rev3rd.com', NULL, NULL, NULL, 13.4, 52.52, ARRAY['fdm'], ARRAY['recycled'], NULL, NULL, NULL, true, false, 0, 0, 'REV3RD specializes in Large Scale Additive Manufacturing, offering innovative and cost-effective solutions for prototypes and projects. The company focuses on pellet extrusion 3D printing, enabling the use of custom and recycled materials. They provide comprehensive services including large-scale 3D printing, laser cutting, material testing, and consulting.', '{"capacity_notes":"REV3RD offers large-scale 3D printing services using their own industrial-grade 3D printers equipped with CNC motion control systems and servo drives. They also provide material testing and development of printing parameters for unique materials and applications.","certifications":[],"industries_served":["Aeronautical","Automotive","Construction"],"overview":"REV3RD specializes in Large Scale Additive Manufacturing, offering innovative and cost-effective solutions for prototypes and projects. The company focuses on pellet extrusion 3D printing, enabling the use of custom and recycled materials. They provide comprehensive services including large-scale 3D printing, laser cutting, material testing, and consulting.","unique_value":"REV3RD distinguishes itself by specializing in Large Scale Additive Manufacturing using pellet extrusion, which allows for the use of innovative and recycled materials, offering affordable feedstocks and faster print times. Their 3D printers utilize industrial CNC motion control systems for industrial-grade reliability and speed."}', '{}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-02-11 02:00:47.015+00', 67, 0, '2025-10-25 16:41:25.326792+00', '2026-03-08 09:58:08.2614+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('af152593-c241-4dc9-aea6-fc7a6adc3501', 'additive-engineering', 'Additive Engineering', 'https://additiveengineering.com', NULL, 'Boston', 'United States', 42.3601, -71.0589, ARRAY['msla'], '{}', NULL, NULL, NULL, true, false, 0, 0, 'Additive Engineering Inc. is a Boston-based rapid product development firm that helps inventors and companies turn concepts into market-ready products. They run over two dozen in-house 3D printers (MSLA is publicly named) and work in 1-4 week agile sprints, delivering functional prototypes, CAD, DfM, materials/process consulting and production-ready engineering drawings. Sales motion is contact-first via email and Calendly -- no instant-quote tool.', '{"capacity_notes":"Offers rapid prototyping services with parts printed within 24 hours. They have a multi-disciplinary team of over twenty engineers, designers, and advisors.","certifications":[],"industries_served":[],"overview":"Additive Engineering Inc. is a Boston-based rapid product development firm helping inventors and companies turn concepts into market-ready products with over two dozen in-house 3D printers (MSLA publicly named) and 1-4 week agile sprints.","unique_value":"Additive Engineering utilizes a unique agile scrum methodology, working in 1-4 week sprints with continuous updates and weekly design review meetings. They emphasize a partnership approach with clients, integrating them into a group chat to guide the product development process. Their expertise includes materials and manufacturing process selection, and preparing detailed manufacturing drawings for seamless transition to high-volume production."}', '{}'::jsonb, NULL, 'within 24 hours (for 3D printing)', true, false, '{}', 'f590f37f-8db5-439a-b4da-ee1b1a455a1e', '2026-04-26 21:30:00+00', 100, 0, '2025-11-11 15:57:15.934661+00', '2026-04-26 21:30:00+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('6f07d806-a7b1-4dde-ad35-982c1c969ec6', 'cosine-additive', 'Cosine Additive – Large Scale 3D Printing & AM Systems', 'https://www.cosineadditive.com/', '8181 W Hardy Rd, Houston, TX 77022, USA', 'Houston', 'United States', 29.835661, -95.356831, ARRAY['fdm'], ARRAY['abs','carbon-fiber','polycarbonate','pc-abs','petg','peek','ultem-9085'], 'white', 'free-listing', 'northamerica', false, false, 0, 0, 'Cosine Additive specializes in large-scale 3D printing services and manufactures the AM1 industrial 3D printer. They offer solutions for rapid prototyping, functional parts, and tooling, particularly for industries like aerospace, automotive, and casting. The company emphasizes open market materials and large print volumes.', NULL, '{"TechnologyID":["fdm"],"affiliatelinkid":"https://www.cosineadditive.com/","cardStyle":"white","categoryLevel1":"northamerica","listingType":"free-listing","location":{"address":"8181 W Hardy Rd, Houston, TX 77022, USA","building":""},"photopolymerid":["polypropylene-p"],"thermoplasticid":["standardpla","carbonfiberreinforcedfilaments","abs-m30-stratasys","polypropylene-mjf","petg","pp-natural","pc"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, false, '{}', NULL, '2026-01-27 11:18:00.275+00', 82, 0, '2025-10-23 16:57:24.633015+00', '2026-03-23 14:52:57.966757+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO suppliers (id, supplier_id, name, website, location_address, location_city, location_country, location_lat, location_lng, technologies, materials, card_style, listing_type, region, verified, premium, rating, review_count, description, description_extended, metadata, logo_url, lead_time_indicator, has_rush_service, has_instant_quote, certifications, country_id, last_validated_at, last_validation_confidence, validation_failures, created_at, updated_at) VALUES ('cfc0118c-65e8-45bb-a60c-578a09afc9af', 'danish-technological-institute', 'Danish Technological Institute – Industrial 3D Printing', 'https://www.dti.dk/services/industrial-3d-printing/40479', 'Taastrup, Denmark', 'Taastrup', 'Denmark', 56.1535426, 10.203355, ARRAY['3d-printing'], ARRAY['stainless-steel-316l','titanium-ti-6al-4v','nylon-pa-12','nylon'], NULL, 'free-listing', 'europe', true, false, 0, 0, 'The Danish Technological Institute is a leading research and technology organization with over 30 years of experience in 3D printing. They specialize in industrial additive manufacturing, offering services from material and process development to production. The institute focuses on delivering innovative solutions and knowledge to Danish companies, particularly in areas like food contact applications and quality assurance.', '{"capacity_notes":"The Danish Technological Institute operates a complete production line for industrial manufacturing with 3D printing and certified laboratories for material characterization within both polymers and metals. They conduct over 350 research and development projects annually and have 70 industry-ready laboratory facilities.","certifications":[],"industries_served":["Food Industry","Medical Industry"],"overview":"The Danish Technological Institute is a leading research and technology organization with over 30 years of experience in 3D printing. They specialize in industrial additive manufacturing, offering services from material and process development to production. The institute focuses on delivering innovative solutions and knowledge to Danish companies, particularly in areas like food contact applications and quality assurance.","unique_value":"The Danish Technological Institute is the only facility in Denmark with an Additive Manufacturing production that complies with food regulations for materials like nylon, titanium, and stainless steel, ensuring full traceability. They also offer proprietary ''3S super smooth surface'' treatment for nylon, improving cleanliness by 12 times, and have developed unique metal and X-ray detectable nylon materials (MDP and Blue DP) for the food industry."}', '{"TechnologyID":["fdm","sls","mjf","dmp"],"affiliatelinkid":"https://www.dti.dk/services/industrial-3d-printing/40479","categoryLevel1":"europe","listingType":"free-listing","location":{"address":"Kongsvang Alle 29, 8000 Aarhus, Denmark","building":""},"metalid":["aluminum-aisi10mg","titanium-ti-6al-4v","steel","stainless-steel-316l","maraging-steel","ni625","inconel-625"],"thermoplasticid":["tpu-mjf","pa11-sls","pa-gf","pa-af","pa-12-carbon-filled","pa-12-bluesint","pa-12","nylon-pa-12-blue-metal","nylon-pa-12","nylon-12-mineral-filled-hst","nylon-12-glass-bead-filled-gf"],"transactionProcessAlias":"default-inquiry/release-1","unitType":"inquiry"}'::jsonb, NULL, NULL, false, true, '{}', '008671b2-ad05-4e60-8622-df1af2c43df2', '2026-02-05 13:03:48.974+00', 83, 1, '2025-10-23 16:57:30.603896+00', '2026-03-08 10:09:46.678516+00') ON CONFLICT (id) DO NOTHING;
